import type { FetchLike } from "./http.js";
import { createJsonHttpClient, HttpError } from "./http.js";

// The HTTP API returns snake_case fields; the `Raw` helpers mirror that
// payload exactly so we can normalize everything to camelCase in one place.
type CommitmentRecordRaw = {
  leaf_index: number;
  commitment: string;
  ephemeral_key: string;
  ciphertext: [string, string, string];
  root: string;
  tx_hash: string;
  inserted_at: number;
  event_type?: string;
  adapter_npk?: string;
  adapter_token?: string;
  adapter_amount?: string;
  adapter_random?: string;
};

export type CommitmentRecord = {
  index: number;
  commitment: string;
  ephemeralKey: string;
  ciphertext: [string, string, string];
  root: string;
  txHash: string;
  insertedAt: number;
  eventType: string;
  adapterNpk?: string;
  adapterToken?: string;
  adapterAmount?: string;
  adapterRandom?: string;
};

type NullifierRecordRaw = {
  nullifier: string;
  tx_hash: string;
  spent_at: number;
  chain_id: number;
};

export type IndexerNullifierRecord = {
  nullifier: string;
  txHash: string;
  spentAt: number;
  chainId: number;
};

type CommitmentBatchResponseRaw = {
  chain_id: number;
  commitments: CommitmentRecordRaw[];
  latest_root: string | null;
};

export type CommitmentBatchResponse = {
  chainId: number;
  commitments: CommitmentRecord[];
  latestRoot: string | null;
};

export type FetchCommitmentsParams = {
  chainId: number;
  start?: number;
  limit?: number;
};

export type GetCommitmentParams = {
  chainId: number;
  commitment: string;
};

export type GetNullifierParams = {
  chainId: number;
  nullifier: string;
};

type NullifierCountResponseRaw = {
  chain_id: number;
  count: number;
};

type CheckNullifiersRaw = {
  found: NullifierRecordRaw[];
};

export type CheckNullifiersParams = {
  chainId: number;
  nullifiers: string[];
};

type IndexerClientDeps = {
  fetch: FetchLike;
};

export function createIndexerClient(baseUrl: string, deps: IndexerClientDeps) {
  const http = createJsonHttpClient(baseUrl, deps);

  const normalizeRecord = (record: CommitmentRecordRaw): CommitmentRecord => ({
    index: record.leaf_index,
    commitment: record.commitment,
    ephemeralKey: record.ephemeral_key,
    ciphertext: [...record.ciphertext] as [string, string, string],
    root: record.root,
    txHash: record.tx_hash,
    insertedAt: record.inserted_at,
    eventType: record.event_type ?? "unknown",
    adapterNpk: record.adapter_npk,
    adapterToken: record.adapter_token,
    adapterAmount: record.adapter_amount,
    adapterRandom: record.adapter_random,
  });

  const normalizeNullifierRecord = (
    record: NullifierRecordRaw,
  ): IndexerNullifierRecord => ({
    nullifier: record.nullifier,
    txHash: record.tx_hash,
    spentAt: record.spent_at,
    chainId: record.chain_id,
  });

  return {
    async fetchCommitmentBatch(
      params: FetchCommitmentsParams,
    ): Promise<CommitmentBatchResponse> {
      const raw = await http.request<CommitmentBatchResponseRaw>({
        method: "GET",
        path: `/chains/${params.chainId}/commitments`,
        query: {
          start: params.start,
          limit: params.limit,
        },
      });
      return {
        chainId: raw.chain_id,
        commitments: raw.commitments.map(normalizeRecord),
        latestRoot: raw.latest_root,
      };
    },
    async getCommitment(
      params: GetCommitmentParams,
    ): Promise<CommitmentRecord> {
      const raw = await http.request<CommitmentRecordRaw | null>({
        method: "GET",
        path: `/chains/${params.chainId}/commitments/${params.commitment}`,
      });
      if (!raw) {
        throw new HttpError("commitment not found", 404, null);
      }
      return normalizeRecord(raw);
    },
    /**
     * Like getCommitment but returns null when the commitment doesn't exist.
     * Used for polling pending deposits without generating console errors.
     */
    async tryGetCommitment(
      params: GetCommitmentParams,
    ): Promise<CommitmentRecord | null> {
      const raw = await http.request<CommitmentRecordRaw | null>({
        method: "GET",
        path: `/chains/${params.chainId}/commitments/${params.commitment}`,
      });
      return raw ? normalizeRecord(raw) : null;
    },
    async getNullifier(
      params: GetNullifierParams,
    ): Promise<IndexerNullifierRecord | null> {
      const raw = await http.request<NullifierRecordRaw | null>({
        method: "GET",
        path: `/chains/${params.chainId}/nullifiers/${params.nullifier}`,
      });
      return raw ? normalizeNullifierRecord(raw) : null;
    },
    async checkNullifiers(
      params: CheckNullifiersParams,
    ): Promise<IndexerNullifierRecord[]> {
      const CHUNK_SIZE = 1000;
      if (params.nullifiers.length <= CHUNK_SIZE) {
        const raw = await http.request<CheckNullifiersRaw>({
          method: "POST",
          path: `/chains/${params.chainId}/nullifiers/check`,
          json: { nullifiers: params.nullifiers },
        });
        return raw.found.map(normalizeNullifierRecord);
      }

      // Chunk into batches of 1000, run sequentially to avoid overwhelming server
      const results: IndexerNullifierRecord[] = [];
      for (let i = 0; i < params.nullifiers.length; i += CHUNK_SIZE) {
        const chunk = params.nullifiers.slice(i, i + CHUNK_SIZE);
        const raw = await http.request<CheckNullifiersRaw>({
          method: "POST",
          path: `/chains/${params.chainId}/nullifiers/check`,
          json: { nullifiers: chunk },
        });
        results.push(...raw.found.map(normalizeNullifierRecord));
      }
      return results;
    },
    async getNullifierCount(chainId: number): Promise<number> {
      const raw = await http.request<NullifierCountResponseRaw>({
        method: "GET",
        path: `/chains/${chainId}/nullifiers/count`,
      });
      return raw.count;
    },
  };
}
