import {
  Contract,
  HDNodeWallet,
  Interface,
  JsonRpcProvider,
  Wallet,
} from "ethers";
import type { TransactionResponse } from "ethers";

import { ETH_TOKEN } from "../../constants.js";
import { zeroize } from "../../crypto/secure-memory.js";
import type { WithdrawResult } from "../types.js";
import type {
  BurnerAccount,
  BurnerAPI,
  BurnerFundParams,
  BurnerSendParams,
  BurnerSweepToPoolParams,
} from "./types.js";

/** Standard BIP-44 path prefix for Ethereum (MetaMask-compatible) */
const BIP44_ETH_PREFIX = "m/44'/60'/0'/0";

export type BurnerServiceDeps = {
  chainRpcUrl: string;
  getMasterSeed: () => Promise<Uint8Array>;
  /** Withdraw from shielded pool to fund a burner address */
  withdrawToAddress: (params: {
    chainId: number;
    poolAddress: string;
    withdrawals: Array<{ token: string; amount: bigint; recipient: string }>;
  }) => Promise<WithdrawResult>;
  /** Build a deposit calldata to sweep tokens back into the pool */
  requestDeposit: (params: {
    chainId: number;
    poolAddress: string;
    depositor: string;
    deposits: Array<{ token: string; amount: bigint }>;
  }) => Promise<{ to: string; calldata: string; value: bigint }>;
};

export type BurnerService = BurnerAPI;

// Minimal ERC-20 ABI for balance checking
const ERC20_BALANCE_OF = "function balanceOf(address) view returns (uint256)";

function isNativeToken(token: string): boolean {
  return token.toLowerCase() === ETH_TOKEN.toLowerCase();
}

export function createBurnerService(deps: BurnerServiceDeps): BurnerService {
  const { chainRpcUrl, getMasterSeed, withdrawToAddress, requestDeposit } =
    deps;
  const provider = new JsonRpcProvider(chainRpcUrl);

  // In-memory caches
  const wallets = new Map<number, Wallet>();
  const nonces = new Map<string, number>();

  async function getWallet(index: number): Promise<Wallet> {
    if (!Number.isInteger(index) || index < 0) {
      throw new Error(`Invalid burner index: ${index}`);
    }
    const cached = wallets.get(index);
    if (cached) return cached;

    const seed = await getMasterSeed();
    try {
      const hd = HDNodeWallet.fromSeed(seed);
      const derived = hd.derivePath(`${BIP44_ETH_PREFIX}/${index}`);
      const wallet = new Wallet(derived.privateKey, provider);

      wallets.set(index, wallet);
      return wallet;
    } finally {
      zeroize(seed);
    }
  }

  // --- Public API ---

  async function addressOf(index: number): Promise<BurnerAccount> {
    const wallet = await getWallet(index);
    return { address: wallet.address, index };
  }

  async function send(
    index: number,
    tx: BurnerSendParams,
  ): Promise<{ txHash: string }> {
    const wallet = await getWallet(index);
    const addrLower = wallet.address.toLowerCase();

    // Use locally tracked nonce to avoid stale provider cache
    const nonce =
      nonces.get(addrLower) ??
      (await provider.getTransactionCount(wallet.address));

    const response: TransactionResponse = await wallet.sendTransaction({
      to: tx.to,
      data: tx.data,
      value: tx.value,
      gasLimit: tx.gasLimit,
      nonce,
    });

    // Increment immediately after submission — a submitted tx consumes the
    // nonce on-chain whether it succeeds or reverts. If sendTransaction itself
    // throws (network error, gas estimation), we never reach here so the nonce
    // stays unchanged.
    nonces.set(addrLower, nonce + 1);

    await response.wait();
    return { txHash: response.hash };
  }

  async function exportKey(index: number): Promise<string> {
    const wallet = await getWallet(index);
    return wallet.privateKey;
  }

  async function getTokenBalance(
    address: string,
    token: string,
  ): Promise<bigint> {
    const iface = new Interface([ERC20_BALANCE_OF]);
    const contract = new Contract(token, iface, provider);
    const bal = await contract.getFunction("balanceOf")(address);
    return BigInt(bal ?? 0);
  }

  async function getBalance(address: string): Promise<bigint> {
    const bal = await provider.getBalance(address);
    return BigInt(bal ?? 0);
  }

  async function fund(
    index: number,
    params: BurnerFundParams,
  ): Promise<WithdrawResult> {
    const { address } = await addressOf(index);
    return withdrawToAddress({
      chainId: params.chainId,
      poolAddress: params.poolAddress,
      withdrawals: [
        { token: params.token, amount: params.amount, recipient: address },
      ],
    });
  }

  async function sweepToPool(
    index: number,
    params: BurnerSweepToPoolParams,
  ): Promise<{ txHash: string }> {
    const { address } = await addressOf(index);
    const native = isNativeToken(params.token);

    // Native ETH requires an explicit amount because the tx needs gas too.
    // Sweep native ETH last so you know how much to deposit.
    if (native && params.amount == null) {
      throw new Error(
        "amount is required for native ETH sweeps (needed to reserve gas)",
      );
    }

    // Resolve amount (full balance if omitted for ERC-20)
    const amount =
      params.amount ?? (await getTokenBalance(address, params.token));
    if (amount === 0n) {
      throw new Error("No token balance to sweep");
    }

    // Build deposit calldata (with final amount)
    const depositResult = await requestDeposit({
      chainId: params.chainId,
      poolAddress: params.poolAddress,
      depositor: address,
      deposits: [{ token: params.token, amount }],
    });

    // ERC-20: approve pool to spend tokens first
    if (!native) {
      const erc20Iface = new Interface([
        "function approve(address spender, uint256 amount)",
      ]);
      const approveData = erc20Iface.encodeFunctionData("approve", [
        params.poolAddress,
        amount,
      ]);
      await send(index, { to: params.token, data: approveData });
    }

    // Execute deposit tx from burner
    const { txHash } = await send(index, {
      to: depositResult.to,
      data: depositResult.calldata,
      value: depositResult.value,
    });

    return { txHash };
  }

  return {
    addressOf,
    send,
    exportKey,
    getTokenBalance,
    getBalance,
    fund,
    sweepToPool,
  };
}
