import type { Account, AccountView } from "../account/account.js";
import type { RelayStatusResponse } from "../clients/broadcaster.js";
import { fetchChainConfig } from "../config.js";
import { initCore } from "../core.js";
import { InitializationError } from "../errors.js";
import type { HistoryEntry } from "../history/types.js";
import type { NoteRecord } from "../state/store/records.js";
import { createIndexedDbStorage } from "../storage/indexeddb.js";
import type {
  DepositRelayResult,
  DepositSyncResult,
  TransactRelayResult,
  TransactSyncResult,
} from "../transactions/types/index.js";
import type { Storage } from "../types.js";
import type { BurnerAccount, BurnerSendParams } from "./burner/types.js";
import { createWalletSDK } from "./sdk.js";
import type {
  InteractResult,
  SendPlanResult,
  SendResult,
  SignerOverride,
  SimpleBurnerFundParams,
  SimpleBurnerSweepToPoolParams,
  SimpleDepositParams,
  SimpleInteractParams,
  SimpleSendParams,
  SimpleTransactParams,
  SimpleWithdrawParams,
  UnlinkCreateConfig,
  UnlinkEvent,
  WalletAccountAPI,
  WalletSDK,
  WithdrawPlanResult,
  WithdrawResult,
} from "./types.js";

/**
 * High-level Unlink SDK entry point that bakes `chainId` and `poolAddress` at construction time.
 *
 * Manages seed, multiple accounts, deposits, transfers, withdrawals, syncing, and events.
 *
 * @example
 * ```ts
 * // Chain mode (auto-resolves chainId, gateway, pool, artifacts):
 * const unlink = await Unlink.create({
 *   chain: "monad-testnet",
 * });
 *
 * // Explicit mode (custom/local deployments):
 * const unlink = await Unlink.create({
 *   chainId: 10143,
 *   poolAddress: "0x...",
 *   gatewayUrl: "http://localhost:3000",
 *   storage: createSqliteStorage({ path: "wallet.db" }),
 * });
 *
 * // Operations — no chainId/poolAddress needed:
 * await unlink.seed.create();
 * await unlink.accounts.create();
 * await unlink.deposit({ depositor: "0x...", deposits: [{ token, amount }] });
 * await unlink.send({ transfers: [{ token, recipient, amount }] });
 * await unlink.getBalances();
 * await unlink.sync();
 * ```
 */
export class Unlink {
  /** @internal */
  private readonly sdk: WalletSDK;

  /** Chain ID this wallet operates on. */
  readonly chainId: number;

  /** Pool contract address this wallet transacts with. */
  readonly poolAddress: string;

  /** Adapter contract address for DeFi operations. */
  readonly adapterAddress: string;

  private constructor(
    sdk: WalletSDK,
    chainId: number,
    poolAddress: string,
    adapterAddress: string,
  ) {
    this.sdk = sdk;
    this.chainId = chainId;
    this.poolAddress = poolAddress;
    this.adapterAddress = adapterAddress;

    this.adapter = {
      address: adapterAddress,
    };
  }

  /**
   * Create a new Unlink instance.
   *
   * Handles all initialization internally:
   * - Resolves chain config (if using `chain` instead of explicit URLs)
   * - Auto-detects storage (IndexedDB in browser) and rng (crypto.getRandomValues)
   * - Runs schema migration via `initCore()`
   * - Creates the internal SDK
   */
  static async create(config: UnlinkCreateConfig): Promise<Unlink> {
    let chainId: number;
    let gatewayUrl: string;
    let poolAddress: string;
    let adapterAddress: string | undefined;
    let proverConfig = config.prover;

    if ("chain" in config) {
      const chainConfig = await fetchChainConfig(config.chain);
      chainId = chainConfig.chainId;
      gatewayUrl = chainConfig.gatewayUrl;
      poolAddress = config.poolAddress ?? chainConfig.poolAddress;
      adapterAddress = config.adapterAddress ?? chainConfig.adapterAddress;
      proverConfig = {
        artifactSource: {
          baseUrl:
            config.prover?.artifactSource?.baseUrl ??
            chainConfig.artifactBaseUrl,
          version:
            config.prover?.artifactSource?.version ??
            chainConfig.artifactVersion,
          preferLocalFiles: config.prover?.artifactSource?.preferLocalFiles,
        },
      };
    } else {
      chainId = config.chainId;
      gatewayUrl = config.gatewayUrl;
      poolAddress = config.poolAddress;
      adapterAddress = config.adapterAddress;

      // Browser mode with explicit URL requires pinned artifact version
      if (
        typeof window !== "undefined" &&
        !config.prover?.artifactSource?.version
      ) {
        throw new InitializationError(
          "prover.artifactSource.version is required in browser when using explicit gatewayUrl mode. " +
            "Use chain mode or provide a pinned artifact version.",
        );
      }
    }

    const storage = config.storage ?? detectStorage();
    const rng = config.rng ?? defaultRng;
    const fetchImpl = config.fetch ?? globalThis.fetch;

    const core = await initCore({ storage, rng });
    const sdk = createWalletSDK(
      { core, fetch: fetchImpl },
      {
        chainId,
        gatewayUrl,
        chainRpcUrl: config.chainRpcUrl,
        prover: proverConfig,
        autoSync: config.autoSync,
      },
    );

    return new Unlink(sdk, chainId, poolAddress, adapterAddress ?? "");
  }

  // ===== Seed Lifecycle =====

  /** Seed management (create, import, export, delete mnemonic). */
  get seed(): WalletSDK["seed"] {
    return this.sdk.seed;
  }

  // ===== Account Management =====

  /** Account management (create, list, switch accounts). */
  get accounts(): WalletAccountAPI {
    return this.sdk.accounts;
  }

  // ===== Core Operations =====

  /**
   * Request a deposit (1 or more tokens).
   * Returns calldata the depositor must submit on-chain via their EOA.
   */
  async deposit(params: SimpleDepositParams): Promise<DepositRelayResult> {
    return this.sdk.deposit.request({
      chainId: this.chainId,
      poolAddress: this.poolAddress,
      depositor: params.depositor,
      deposits: params.deposits,
      account: params.account,
    });
  }

  /** Wait for a deposit to be confirmed on-chain. */
  async confirmDeposit(relayId: string): Promise<DepositSyncResult> {
    return this.sdk.deposit.reconcile(relayId);
  }

  /**
   * Send a private transfer (1 or more recipients).
   * Handles note selection, circuit selection, and proof generation automatically.
   */
  async send(
    params: SimpleSendParams,
    overrides?: SignerOverride,
  ): Promise<SendResult> {
    return this.sdk.transfer.send(
      {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        transfers: params.transfers,
      },
      overrides,
    );
  }

  /**
   * Get a send plan without executing (for preview/confirmation UIs).
   */
  async planSend(
    params: SimpleSendParams,
    account?: AccountView,
  ): Promise<SendPlanResult> {
    return this.sdk.transfer.plan(
      {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        transfers: params.transfers,
      },
      account,
    );
  }

  /** Execute a pre-built send plan. */
  async executeSend(
    plans: SendPlanResult,
    overrides?: SignerOverride,
  ): Promise<SendResult> {
    return this.sdk.transfer.execute(
      plans,
      { chainId: this.chainId, poolAddress: this.poolAddress },
      overrides,
    );
  }

  /**
   * Execute a withdrawal (1 or more recipients).
   * Handles note selection, circuit selection, and proof generation automatically.
   */
  async withdraw(
    params: SimpleWithdrawParams,
    overrides?: SignerOverride,
  ): Promise<WithdrawResult> {
    return this.sdk.withdraw.send(
      {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        withdrawals: params.withdrawals,
      },
      overrides,
    );
  }

  /**
   * Get a withdrawal plan without executing (for preview/confirmation UIs).
   */
  async planWithdraw(
    params: SimpleWithdrawParams,
    account?: AccountView,
  ): Promise<WithdrawPlanResult> {
    return this.sdk.withdraw.plan(
      {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        withdrawals: params.withdrawals,
      },
      account,
    );
  }

  /** Execute a pre-built withdrawal plan. */
  async executeWithdraw(
    plans: WithdrawPlanResult,
    overrides?: SignerOverride,
  ): Promise<WithdrawResult> {
    return this.sdk.withdraw.execute(
      plans,
      { chainId: this.chainId, poolAddress: this.poolAddress },
      overrides,
    );
  }

  /** Wait for a transfer or withdrawal to be confirmed on-chain. */
  async confirmTransaction(relayId: string): Promise<TransactSyncResult> {
    return this.sdk.transact.reconcile(relayId);
  }

  // ===== Queries =====

  /**
   * Get balance for a specific token (defaults to all tokens if no token specified).
   * @param token Token address. If omitted, returns balance for all tokens via getBalances().
   */
  async getBalance(
    token: string,
    overrides?: { account: AccountView },
  ): Promise<bigint> {
    return this.sdk.balances.get(this.chainId, token, overrides);
  }

  /** Get balances for all tokens. */
  async getBalances(overrides?: {
    account: AccountView;
  }): Promise<Record<string, bigint>> {
    return this.sdk.balances.list(this.chainId, overrides);
  }

  /** Get transaction history. */
  async getHistory(
    options?: { includeSelfSends?: boolean },
    overrides?: { account: AccountView },
  ): Promise<HistoryEntry[]> {
    return this.sdk.history.list(this.chainId, options, overrides);
  }

  /** Get UTXO notes for the active account (or override account). */
  async getNotes(overrides?: { account: AccountView }): Promise<NoteRecord[]> {
    return this.sdk.notes.list(this.chainId, overrides);
  }

  // ===== Sync =====

  /**
   * Sync notes from the blockchain.
   * Automatically resolves the active account (no need to pass it).
   */
  async sync(
    options?: { forceFullResync?: boolean },
    overrides?: { account: AccountView },
  ): Promise<void> {
    const account = overrides?.account ?? (await this.requireActiveAccount());
    return this.sdk.sync.syncChain(this.chainId, account, options);
  }

  /** Start auto-sync at the given interval (default: 5000ms). */
  startAutoSync(intervalMs?: number): void {
    void this.sdk.sync.startAutoSync(intervalMs);
  }

  /** Stop auto-sync. */
  stopAutoSync(): void {
    this.sdk.sync.stopAutoSync();
  }

  // ===== Transaction Status =====

  /** Get the current status of a transaction. */
  async getTxStatus(txId: string): Promise<RelayStatusResponse> {
    return this.sdk.tx.getStatus(txId);
  }

  /** Start tracking a transaction for status-changed events. */
  trackTx(txId: string): void {
    this.sdk.tx.track(txId);
  }

  /** Stop tracking a transaction. */
  untrackTx(txId: string): void {
    this.sdk.tx.untrack(txId);
  }

  // ===== Events =====

  /**
   * Subscribe to wallet events (notes-updated, sync-error, tx-status-changed, etc.).
   * @returns Unsubscribe function.
   */
  on(listener: (event: UnlinkEvent) => void): () => void {
    return this.sdk.events.on(listener);
  }

  // ===== Burner =====

  /**
   * Burner account operations (BIP-44 derived EOAs for DeFi interactions).
   * chainId/poolAddress are injected automatically for fund/sweepToPool.
   */
  readonly burner = {
    /** Derive burner address for a given index. */
    addressOf: (index: number): Promise<BurnerAccount> => {
      return this.sdk.burner.addressOf(index);
    },

    /** Send a transaction from burner at index. */
    send: (
      index: number,
      tx: BurnerSendParams,
    ): Promise<{ txHash: string }> => {
      return this.sdk.burner.send(index, tx);
    },

    /** Export the raw private key (0x-prefixed hex) for wallet import. */
    exportKey: (index: number): Promise<string> => {
      return this.sdk.burner.exportKey(index);
    },

    /** Withdraw from shielded pool to fund this burner. */
    fund: (
      index: number,
      params: SimpleBurnerFundParams,
    ): Promise<WithdrawResult> => {
      return this.sdk.burner.fund(index, {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        token: params.token,
        amount: params.amount,
      });
    },

    /** Approve + deposit tokens from burner back into shielded pool. */
    sweepToPool: (
      index: number,
      params: SimpleBurnerSweepToPoolParams,
    ): Promise<{ txHash: string }> => {
      return this.sdk.burner.sweepToPool(index, {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        token: params.token,
        amount: params.amount,
      });
    },

    /** Get ERC-20 token balance of any address. */
    getTokenBalance: (address: string, token: string): Promise<bigint> => {
      return this.sdk.burner.getTokenBalance(address, token);
    },

    /** Get native ETH balance of any address. */
    getBalance: (address: string): Promise<bigint> => {
      return this.sdk.burner.getBalance(address);
    },
  };

  // ===== Interact (Private DeFi) =====

  /**
   * Adapter contract address (resolved from config).
   * Use for building DeFi calls that reference the adapter.
   */
  readonly adapter: {
    readonly address: string;
  };

  /**
   * Execute an atomic unshield -> DeFi call(s) -> reshield flow through an adapter.
   * chainId/poolAddress/adapterAddress are injected automatically.
   */
  async interact(
    params: SimpleInteractParams,
    opts?: { skipBroadcast?: boolean },
    overrides?: SignerOverride,
  ): Promise<InteractResult> {
    return this.sdk.adapter.execute(
      {
        chainId: this.chainId,
        poolAddress: this.poolAddress,
        adapterAddress: this.adapterAddress,
        spend: params.spend,
        calls: params.calls,
        receive: params.receive,
        deadline: params.deadline,
      },
      opts,
      overrides,
    );
  }

  // ===== Advanced =====

  /**
   * Advanced escape hatch for raw JoinSplit transaction building.
   * Use this for custom transaction construction (e.g. swap adapters).
   */
  readonly advanced = {
    /** Build and submit raw JoinSplit transactions. */
    transact: (
      params: SimpleTransactParams,
      opts?: { skipBroadcast?: boolean },
    ): Promise<TransactRelayResult> => {
      return this.sdk.transact.transact(
        {
          chainId: this.chainId,
          poolAddress: this.poolAddress,
          transactions: params.transactions,
        },
        opts,
      );
    },

    /** Wait for a raw transaction to be confirmed on-chain. */
    reconcile: (relayId: string): Promise<TransactSyncResult> => {
      return this.sdk.transact.reconcile(relayId);
    },
  };

  // ===== Private Helpers =====

  private async requireActiveAccount(): Promise<Account> {
    const account = await this.sdk.accounts.getActive();
    if (!account) {
      throw new Error("No active account. Create an account first.");
    }
    return account;
  }
}

// ===== Auto-detection helpers =====

function detectStorage(): Storage {
  if (
    typeof globalThis.indexedDB !== "undefined" &&
    typeof globalThis.window !== "undefined"
  ) {
    return createIndexedDbStorage({ name: "unlink-wallet" });
  }
  throw new InitializationError(
    "No storage backend detected. In Node.js, provide a storage option " +
      "(e.g. createSqliteStorage or createMemoryStorage).",
  );
}

const defaultRng = (n: number): Uint8Array => {
  if (!globalThis.crypto?.getRandomValues) {
    throw new InitializationError(
      "crypto.getRandomValues unavailable. Provide a custom rng in config.",
    );
  }
  return globalThis.crypto.getRandomValues(new Uint8Array(n));
};

/** @deprecated Use {@link Unlink} instead. */
export const UnlinkWallet = Unlink;
/** @deprecated Use {@link Unlink} instead. */
export type UnlinkWallet = Unlink;
