import { ed25519, x25519 } from "@noble/curves/ed25519.js";

import { CoreError } from "../errors.js";
import { FieldSize, Hex } from "../keys/hex.js";
import type { Ciphertext, NoteInput } from "../transactions/types/index.js";
import { parseHexToBigInt } from "../utils/bigint.js";
import { SNARK_SCALAR_FIELD } from "../utils/validators.js";
import { poseidon } from "./adapters/index.js";

/**
 * Derive a 3-element keystream from an ECDH shared secret.
 * keystream[i] = Poseidon(sharedSecretScalar, i)
 */
function deriveKeystream(sharedSecret: Uint8Array): [bigint, bigint, bigint] {
  const scalar =
    BigInt("0x" + Hex.fromBytes(sharedSecret)) % SNARK_SCALAR_FIELD;
  return [
    poseidon([scalar, 0n]),
    poseidon([scalar, 1n]),
    poseidon([scalar, 2n]),
  ];
}

/**
 * Encrypt a note for the holder of the given Ed25519 viewing public key.
 * Uses X25519 ECDH + field addition mod SNARK_SCALAR_FIELD.
 */
export function encryptNote(
  note: NoteInput,
  recipientViewingPubKey: Uint8Array,
): Ciphertext {
  const recipientX25519 = ed25519.utils.toMontgomery(recipientViewingPubKey);
  const ephPriv = x25519.utils.randomSecretKey();
  const ephPub = x25519.getPublicKey(ephPriv);
  const sharedSecret = x25519.getSharedSecret(ephPriv, recipientX25519);

  const keystream = deriveKeystream(sharedSecret);
  const plaintext: [bigint, bigint, bigint] = [
    note.random,
    parseHexToBigInt(note.token),
    note.amount,
  ];

  return {
    ephemeralKey: BigInt("0x" + Hex.fromBytes(ephPub)),
    data: [
      (plaintext[0] + keystream[0]) % SNARK_SCALAR_FIELD,
      (plaintext[1] + keystream[1]) % SNARK_SCALAR_FIELD,
      (plaintext[2] + keystream[2]) % SNARK_SCALAR_FIELD,
    ],
  };
}

/**
 * Decrypt a ciphertext using the recipient's Ed25519 viewing private key.
 * Reverses field addition: plaintext = (ciphertext - keystream + p) mod p
 *
 * **Important:** This decryption is unauthenticated. Callers MUST verify the
 * output by recomputing the commitment (Poseidon(npk, token, amount)) and
 * comparing it against the on-chain value. See note-sync.ts for the pattern.
 */
export function decryptNote(
  c: Ciphertext,
  viewingPrivKey: Uint8Array,
): { random: bigint; token: string; amount: bigint } {
  const myX25519 = ed25519.utils.toMontgomerySecret(viewingPrivKey);
  const ephPub = Hex.toBytes(Hex.fromBigInt(c.ephemeralKey, FieldSize.SCALAR));
  const sharedSecret = x25519.getSharedSecret(myX25519, ephPub);

  const keystream = deriveKeystream(sharedSecret);

  const random =
    (c.data[0] - keystream[0] + SNARK_SCALAR_FIELD) % SNARK_SCALAR_FIELD;
  const tokenBigint =
    (c.data[1] - keystream[1] + SNARK_SCALAR_FIELD) % SNARK_SCALAR_FIELD;
  const amount =
    (c.data[2] - keystream[2] + SNARK_SCALAR_FIELD) % SNARK_SCALAR_FIELD;

  if (tokenBigint > 0xffffffffffffffffffffffffffffffffffffffffn) {
    throw new CoreError("Invalid Decrypt");
  }

  return {
    random,
    token: "0x" + tokenBigint.toString(16).padStart(40, "0"),
    amount,
  };
}

export function deriveCommitment(note: {
  npk: bigint;
  amount: bigint;
  token: string;
}) {
  const tokenScalar = BigInt(note.token);
  return poseidon([note.npk, tokenScalar, note.amount]);
}

/**
 * Derive the nullifier public key (npk) from a note.
 */
export function deriveNpk(note: NoteInput) {
  return poseidon([note.mpk, note.random]);
}

/**
 * Compute the commitment for a note given its npk.
 */
export function computeCommitment(note: NoteInput, npk: bigint) {
  const tokenScalar = BigInt(note.token);
  return poseidon([npk, tokenScalar, note.amount]);
}
