import { CoreError, ReconcileError } from "../errors.js";
import type { JobKind, JobRecord, JobStatus } from "../state/index.js";
import type {
  BaseStateStore,
  DepositSyncResult,
  TransactSyncResult,
} from "./types/index.js";

type ReconcilerDeps = {
  stateStore: BaseStateStore;
  depositClient: {
    syncPendingDeposit: (relayId: string) => Promise<DepositSyncResult>;
  };
  transactService: {
    syncPendingTransact: (relayId: string) => Promise<TransactSyncResult>;
  };
};

const ACTIVE_STATUSES: JobStatus[] = ["pending", "submitted", "broadcasting"];

export function createJobReconciler(deps: ReconcilerDeps) {
  const { stateStore, depositClient, transactService } = deps;

  async function markChecked(job: JobRecord, err?: unknown) {
    const latest = (await stateStore.getJob(job.relayId)) ?? job;
    const message =
      err instanceof Error
        ? err.message
        : err !== undefined
          ? String(err)
          : null;
    await stateStore.putJob({
      ...latest,
      lastCheckedAt: Date.now(),
      ...(message ? { error: message } : {}),
    });
  }

  async function markDead(job: JobRecord, reason: string) {
    const latest = (await stateStore.getJob(job.relayId)) ?? job;
    if (latest.status === "succeeded") return;
    await stateStore.putJob({
      ...latest,
      status: "dead",
      lastCheckedAt: Date.now(),
      error: reason,
    });
  }

  function isTimedOut(job: JobRecord) {
    return Date.now() - job.createdAt > job.timeoutMs;
  }

  async function reconcileJob(job: JobRecord) {
    const latest = (await stateStore.getJob(job.relayId)) ?? job;
    if (!ACTIVE_STATUSES.includes(latest.status)) {
      if (latest.status === "failed" || latest.status === "dead") {
        throw new ReconcileError(
          latest.error ?? `job ${latest.status}`,
          latest.status,
        );
      }
      // Job already succeeded (e.g. auto-sync reconciled it).
      // Re-run sync (idempotent) to return a valid result.
      if (latest.kind === "deposit") {
        return depositClient.syncPendingDeposit(latest.relayId);
      }
      return transactService.syncPendingTransact(latest.relayId);
    }
    if (latest.status !== "succeeded" && isTimedOut(latest)) {
      await markDead(latest, "job timed out");
      const current = await stateStore.getJob(latest.relayId);
      if (current?.status === "succeeded") {
        // Job succeeded between markDead check — re-sync (idempotent).
        if (current.kind === "deposit") {
          return depositClient.syncPendingDeposit(current.relayId);
        }
        return transactService.syncPendingTransact(current.relayId);
      }
      throw new ReconcileError("job timed out", "dead");
    }
    if (latest.kind === "deposit") {
      return depositClient.syncPendingDeposit(latest.relayId);
    }
    return transactService.syncPendingTransact(latest.relayId);
  }

  async function reconcileRelay(relayId: string) {
    const job = await stateStore.getJob(relayId);
    if (!job) {
      throw new CoreError(`unknown relay ${relayId}`);
    }
    try {
      const res = await reconcileJob(job);
      await markChecked(job);
      return res;
    } catch (err) {
      await markChecked(job, err);
      throw err;
    }
  }

  async function reconcileAll(
    filter: {
      kind?: JobKind;
      statuses?: JobStatus[];
    } = {},
  ) {
    const jobs = await stateStore.listJobs({
      kind: filter.kind,
      statuses: filter.statuses ?? ACTIVE_STATUSES,
    });
    const results = [];
    for (const job of jobs) {
      try {
        const res = await reconcileJob(job);
        await markChecked(job);
        results.push(res);
      } catch (err) {
        await markChecked(job, err);
        // Allow caller to decide how to handle errors; we keep going.
        results.push(err);
      }
    }
    return results;
  }

  return {
    reconcileRelay,
    reconcileAll,
  };
}
