import { Groth16Proof, PublicSignals } from "snarkjs";
import * as snarkjs from "snarkjs";

import { ProofError } from "../errors.js";
import {
  ArtifactType,
  assertValidArtifactVersion,
  buildR2ArtifactUrl,
  buildR2ChecksumsUrl,
  getLocalArtifactPath,
  requireRemoteArtifactSource,
  resolveArtifactSourceConfig,
  Runtime,
  type ArtifactSourceConfig,
  type RemoteArtifactSourceConfig,
  type ResolvedArtifactSourceConfig,
} from "./config.js";
import {
  ArtifactIntegrityError,
  isArtifactIntegrityError,
  parseChecksumsManifest,
  verifyArtifactIntegrity,
} from "./integrity.js";
import {
  getCircuitConfig,
  SUPPORTED_CIRCUITS,
  type CircuitConfig,
} from "./registry.js";

interface LoadedArtifacts {
  readonly wasm: Uint8Array;
  readonly zkey: Uint8Array;
  readonly vkey: VerificationKey;
}

// Cache loaded artifacts to avoid reloading large files on repeated calls.
const MAX_ARTIFACT_CACHE_ENTRIES = 16;
const artifactCache = new Map<string, LoadedArtifacts>();

export interface ProverOptions {
  /**
   * Artifact source selection for R2 pathing and local-first mode.
   */
  readonly artifactSource?: ArtifactSourceConfig;
}

export interface JoinsplitProof {
  readonly proof: Groth16Proof;
  readonly publicSignals: PublicSignals;
}

export interface VerificationKey {
  readonly protocol: string;
  readonly curve: string;
  readonly nPublic: number;
  readonly vk_alpha_1: string[];
  readonly vk_beta_2: string[][];
  readonly vk_gamma_2: string[][];
  readonly vk_delta_2: string[][];
  readonly vk_alphabeta_12: string[][][];
  readonly IC: string[][];
}

export interface JoinsplitProofInput {
  readonly merkleRoot: bigint;
  readonly boundParamsHash: bigint;
  readonly nullifiers: bigint[];
  readonly commitmentsOut: bigint[];
  readonly token: bigint;
  readonly publicKey: bigint[];
  readonly signature: bigint[];
  readonly randomIn: bigint[];
  readonly valueIn: bigint[];
  readonly pathElements: bigint[][];
  readonly leavesIndices: bigint[];
  readonly nullifyingKey: bigint;
  readonly npkOut: bigint[];
  readonly valueOut: bigint[];
}

/**
 * Select the appropriate circuit based on input/output dimensions
 * @param inputs Number of inputs (nullifiers)
 * @param outputs Number of outputs (commitments)
 * @returns Circuit configuration
 * @throws ProofError if no matching circuit is found
 */
function selectCircuit(inputs: number, outputs: number): CircuitConfig {
  const config = getCircuitConfig(inputs, outputs);

  if (!config) {
    throw new ProofError(
      `No circuit available for ${inputs} inputs and ${outputs} outputs. ` +
        `Supported circuits: ${SUPPORTED_CIRCUITS.join(", ")}`,
    );
  }

  return config;
}

function getErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  return String(error);
}

function toProofError(error: unknown): ProofError {
  if (error instanceof ProofError) {
    return error;
  }
  return new ProofError(getErrorMessage(error));
}

function resolveArtifactSource(
  options?: ProverOptions,
): ResolvedArtifactSourceConfig {
  return resolveArtifactSourceConfig(options?.artifactSource);
}

function resolveNodeRemoteFallbackSource(
  source: ResolvedArtifactSourceConfig,
): RemoteArtifactSourceConfig | null {
  if (source.version) {
    return requireRemoteArtifactSource(source);
  }

  const envVersionRaw =
    typeof process !== "undefined" ? process.env.UNLINK_ARTIFACT_VERSION : "";
  const envVersion = (envVersionRaw ?? "").trim().replace(/^\/+|\/+$/g, "");

  if (envVersion.length === 0) {
    return null;
  }
  try {
    assertValidArtifactVersion(envVersion, "UNLINK_ARTIFACT_VERSION");
  } catch (error) {
    throw new ProofError(getErrorMessage(error));
  }

  return {
    baseUrl: source.baseUrl,
    version: envVersion,
  };
}

function getNodeFallbackVersionCacheHint(): string {
  const envVersionRaw =
    typeof process !== "undefined" ? process.env.UNLINK_ARTIFACT_VERSION : "";
  const envVersion = (envVersionRaw ?? "").trim().replace(/^\/+|\/+$/g, "");
  return envVersion.length > 0 ? envVersion : "no-env-version";
}

function getArtifactCacheKey(
  circuitName: string,
  source: ResolvedArtifactSourceConfig,
): string {
  const nodeFallbackVersion =
    Runtime.isNode() && source.preferLocalFiles && !source.version
      ? getNodeFallbackVersionCacheHint()
      : "n/a";

  return [
    Runtime.getEnvironment(),
    circuitName,
    source.baseUrl,
    source.version ?? "no-version",
    source.preferLocalFiles ? "local-first" : "remote-first",
    `node-fallback:${nodeFallbackVersion}`,
  ].join("|");
}

function cacheArtifacts(
  cacheKey: string,
  artifacts: LoadedArtifacts,
): LoadedArtifacts {
  if (artifactCache.has(cacheKey)) {
    artifactCache.delete(cacheKey);
  }
  artifactCache.set(cacheKey, artifacts);

  while (artifactCache.size > MAX_ARTIFACT_CACHE_ENTRIES) {
    const oldestKey = artifactCache.keys().next().value as string | undefined;
    if (!oldestKey) {
      break;
    }
    artifactCache.delete(oldestKey);
  }

  return artifacts;
}

function readCachedArtifacts(cacheKey: string): LoadedArtifacts | undefined {
  const cached = artifactCache.get(cacheKey);
  if (!cached) {
    return undefined;
  }

  // Refresh recency for LRU behavior.
  artifactCache.delete(cacheKey);
  artifactCache.set(cacheKey, cached);
  return cached;
}

/**
 * Fetch circuit artifacts from remote artifact host or local files.
 */
async function fetchCircuitArtifacts(
  circuitName: string,
  options?: ProverOptions,
): Promise<LoadedArtifacts> {
  const source = resolveArtifactSource(options);
  const cacheKey = getArtifactCacheKey(circuitName, source);

  const cachedArtifacts = readCachedArtifacts(cacheKey);
  if (cachedArtifacts) {
    return cachedArtifacts;
  }

  if (Runtime.isBrowser()) {
    if (source.preferLocalFiles) {
      throw new ProofError(
        "artifactSource.preferLocalFiles is only supported in Node.js",
      );
    }

    const remoteArtifacts = await fetchFromRemoteSources(
      circuitName,
      requireRemoteArtifactSource(source),
    );
    return cacheArtifacts(cacheKey, remoteArtifacts);
  }

  if (Runtime.isNode()) {
    if (source.preferLocalFiles) {
      try {
        const localArtifacts = await fetchFromLocalFiles(circuitName);
        return cacheArtifacts(cacheKey, localArtifacts);
      } catch (localError) {
        const remoteSource = resolveNodeRemoteFallbackSource(source);
        if (!remoteSource) {
          throw new ProofError(
            `failed to load artifacts for ${circuitName}. ` +
              `Local error: ${getErrorMessage(localError)}. ` +
              "Remote fallback disabled because no pinned artifact version is configured. " +
              "Set artifactSource.version or UNLINK_ARTIFACT_VERSION.",
          );
        }
        try {
          const remoteArtifacts = await fetchFromRemoteSources(
            circuitName,
            remoteSource,
          );
          return cacheArtifacts(cacheKey, remoteArtifacts);
        } catch (remoteError) {
          throw new ProofError(
            `failed to load artifacts for ${circuitName}. ` +
              `Local error: ${getErrorMessage(localError)}. ` +
              `Remote error: ${getErrorMessage(remoteError)}`,
          );
        }
      }
    }

    const remoteSource = requireRemoteArtifactSource(source);
    try {
      const remoteArtifacts = await fetchFromRemoteSources(
        circuitName,
        remoteSource,
      );
      return cacheArtifacts(cacheKey, remoteArtifacts);
    } catch (remoteError) {
      // Remote-first mode never falls back to local files to avoid silent drift.
      if (
        remoteError instanceof ProofError ||
        isArtifactIntegrityError(remoteError)
      ) {
        throw remoteError;
      }
      throw new ProofError(
        `failed to load artifacts for ${circuitName}. ` +
          `Remote error: ${getErrorMessage(remoteError)}`,
      );
    }
  }

  throw new ProofError(`unsupported runtime: ${Runtime.getEnvironment()}`);
}

async function fetchFromRemoteSources(
  circuitName: string,
  source: RemoteArtifactSourceConfig,
): Promise<LoadedArtifacts> {
  try {
    return await fetchFromR2(circuitName, source);
  } catch (error) {
    if (error instanceof ProofError) {
      throw error;
    }
    throw new ProofError(
      `failed to fetch artifacts for ${circuitName} from ` +
        `${source.baseUrl}/${source.version}: ${getErrorMessage(error)}`,
    );
  }
}

async function fetchFromR2(
  circuitName: string,
  source: RemoteArtifactSourceConfig,
): Promise<LoadedArtifacts> {
  const checksumsUrl = buildR2ChecksumsUrl(circuitName, source);
  const checksumsRes = await fetch(checksumsUrl);

  if (!checksumsRes.ok) {
    throw new ProofError(
      `failed to fetch checksums manifest for ${circuitName} from ${checksumsUrl}. ` +
        `Status: ${checksumsRes.status}`,
    );
  }

  let checksumsJson: unknown;
  try {
    checksumsJson = await checksumsRes.json();
  } catch (error) {
    throw new ArtifactIntegrityError(
      `invalid checksums manifest JSON for ${circuitName}: ${getErrorMessage(error)}`,
    );
  }
  const checksums = parseChecksumsManifest(
    checksumsJson,
    circuitName,
    source.version,
  );

  const wasmUrl = buildR2ArtifactUrl(circuitName, ArtifactType.WASM, source);
  const zkeyUrl = buildR2ArtifactUrl(circuitName, ArtifactType.ZKEY, source);
  const vkeyUrl = buildR2ArtifactUrl(circuitName, ArtifactType.VKEY, source);

  const [wasmRes, zkeyRes, vkeyRes] = await Promise.all([
    fetch(wasmUrl),
    fetch(zkeyUrl),
    fetch(vkeyUrl),
  ]);

  if (!wasmRes.ok || !zkeyRes.ok || !vkeyRes.ok) {
    throw new ProofError(
      `failed to fetch artifacts for ${circuitName} from ${source.baseUrl}/${source.version}. ` +
        `Status: wasm=${wasmRes.status}, zkey=${zkeyRes.status}, vkey=${vkeyRes.status}`,
    );
  }

  const [wasm, zkey, vkeyBytes] = await Promise.all([
    wasmRes.arrayBuffer().then((buffer) => new Uint8Array(buffer)),
    zkeyRes.arrayBuffer().then((buffer) => new Uint8Array(buffer)),
    vkeyRes.arrayBuffer().then((buffer) => new Uint8Array(buffer)),
  ]);

  await Promise.all([
    verifyArtifactIntegrity(checksums, circuitName, ArtifactType.WASM, wasm),
    verifyArtifactIntegrity(checksums, circuitName, ArtifactType.ZKEY, zkey),
    verifyArtifactIntegrity(
      checksums,
      circuitName,
      ArtifactType.VKEY,
      vkeyBytes,
    ),
  ]);

  const vkeyText = new TextDecoder().decode(vkeyBytes);
  let vkey: VerificationKey;
  try {
    vkey = JSON.parse(vkeyText) as VerificationKey;
  } catch (error) {
    throw new ArtifactIntegrityError(
      `invalid verification key JSON for ${circuitName}: ${getErrorMessage(error)}`,
    );
  }

  return { wasm, zkey, vkey };
}

async function fetchFromLocalFiles(
  circuitName: string,
): Promise<LoadedArtifacts> {
  const wasmCandidates = getLocalArtifactPath(circuitName, ArtifactType.WASM);
  const zkeyCandidates = getLocalArtifactPath(circuitName, ArtifactType.ZKEY);
  const vkeyCandidates = getLocalArtifactPath(circuitName, ArtifactType.VKEY);

  let wasm: Uint8Array | undefined;
  let zkey: Uint8Array | undefined;
  let vkey: VerificationKey | undefined;

  let wasmLoaded = false;
  for (const candidate of wasmCandidates) {
    try {
      wasm = await readBinaryResource(candidate);
      wasmLoaded = true;
      break;
    } catch {
      // Try next candidate.
    }
  }

  if (!wasmLoaded) {
    throw new ProofError(
      `Could not find WASM artifact for ${circuitName}. ` +
        `Please run 'pnpm run build:all' in the circuits package.`,
    );
  }

  let zkeyLoaded = false;
  for (const candidate of zkeyCandidates) {
    try {
      zkey = await readBinaryResource(candidate);
      zkeyLoaded = true;
      break;
    } catch {
      // Try next candidate.
    }
  }

  if (!zkeyLoaded) {
    throw new ProofError(
      `Could not find zkey artifact for ${circuitName}. ` +
        `Please run 'pnpm run build:all' in the circuits package.`,
    );
  }

  let vkeyLoaded = false;
  for (const candidate of vkeyCandidates) {
    try {
      const vkeyText = await readTextResource(candidate);
      vkey = JSON.parse(vkeyText);
      vkeyLoaded = true;
      break;
    } catch {
      // Try next candidate.
    }
  }

  if (!vkeyLoaded) {
    throw new ProofError(
      `Could not find verification key for ${circuitName}. ` +
        `Please run 'pnpm run build:all' in the circuits package.`,
    );
  }

  return { wasm: wasm!, zkey: zkey!, vkey: vkey! };
}

async function readBinaryResource(relativePath: string): Promise<Uint8Array> {
  const url = new URL(relativePath, import.meta.url);

  try {
    if (url.protocol === "file:") {
      const fs = (await import("fs")).default;
      const readPromise: Promise<Buffer> = new Promise((resolve, reject) => {
        fs.readFile(url.pathname, (err, data) => {
          if (err) {
            reject(err);
          } else {
            resolve(data);
          }
        });
      });
      const buf = await readPromise;
      return new Uint8Array(buf);
    }
    const response = await fetch(url);
    if (!response.ok) {
      throw new ProofError(
        `failed to fetch ${relativePath}: ${response.statusText}`,
      );
    }
    return new Uint8Array(await response.arrayBuffer());
  } catch (error) {
    throw new ProofError(
      `failed to read binary resource ${relativePath}: ${
        (error as Error).message
      }`,
    );
  }
}

async function readTextResource(relativePath: string): Promise<string> {
  const url = new URL(relativePath, import.meta.url);
  if (url.protocol === "file:") {
    const fs = (await import("fs")).default;
    const readPromise: Promise<Buffer> = new Promise((resolve, reject) => {
      fs.readFile(url.pathname, (err, data) => {
        if (err) {
          reject(err);
        } else {
          resolve(data);
        }
      });
    });
    const buf = await readPromise;
    return buf.toString("utf-8");
  }

  const response = await fetch(url);
  if (!response.ok) {
    throw new ProofError(
      `failed to fetch ${relativePath}: ${response.statusText}`,
    );
  }
  return response.text();
}

export async function proveTransaction(
  input: JoinsplitProofInput,
  options?: ProverOptions,
): Promise<JoinsplitProof> {
  try {
    const nInputs = input.nullifiers.length;
    const nOutputs = input.commitmentsOut.length;

    const circuit = selectCircuit(nInputs, nOutputs);

    const { wasm, vkey, zkey } = await fetchCircuitArtifacts(
      circuit.name,
      options,
    );

    const inputSignals = input as unknown as Record<
      string,
      bigint | bigint[] | string
    >;

    const { proof, publicSignals } = await snarkjs.groth16.fullProve(
      inputSignals,
      wasm,
      zkey,
    );

    const isValid = await snarkjs.groth16.verify(vkey, publicSignals, proof);
    if (!isValid) {
      throw new ProofError("generated proof is invalid");
    }

    return {
      proof,
      publicSignals,
    };
  } catch (error) {
    throw new ProofError(
      "proof generation failed: " + toProofError(error).message,
    );
  }
}

/**
 * Get verification key for a specific circuit configuration.
 */
export async function getVerificationKey(
  inputs: number,
  outputs: number,
  options?: ProverOptions,
): Promise<VerificationKey> {
  try {
    const circuit = selectCircuit(inputs, outputs);
    const { vkey } = await fetchCircuitArtifacts(circuit.name, options);
    return vkey;
  } catch (error) {
    throw new ProofError(
      "failed to load verification key: " + toProofError(error).message,
    );
  }
}

/**
 * Verify a proof with public signals.
 * Auto-detects the circuit from the public signals structure.
 */
export async function verifyProof(
  proof: Groth16Proof,
  publicSignals: PublicSignals,
  options?: ProverOptions,
): Promise<boolean> {
  try {
    const totalLength = publicSignals.length;
    const variableCount = totalLength - 2;

    let vkey: VerificationKey | null = null;
    for (const circuitKey of SUPPORTED_CIRCUITS) {
      const parts = circuitKey.split("x");
      const config = getCircuitConfig(parseInt(parts[0]!), parseInt(parts[1]!));
      if (config && config.inputs + config.outputs === variableCount) {
        const artifacts = await fetchCircuitArtifacts(config.name, options);
        vkey = artifacts.vkey;
        break;
      }
    }

    if (!vkey) {
      throw new ProofError(
        `Could not determine circuit from ${totalLength} public signals`,
      );
    }

    return await snarkjs.groth16.verify(vkey, publicSignals, proof);
  } catch (error) {
    throw new ProofError(
      "proof verification failed: " + toProofError(error).message,
    );
  }
}

/**
 * Verify a proof with explicit circuit specification.
 * Preferred method when you know the circuit dimensions.
 */
export async function verifyProofWithCircuit(
  proof: Groth16Proof,
  publicSignals: PublicSignals,
  inputs: number,
  outputs: number,
  options?: ProverOptions,
): Promise<boolean> {
  try {
    const circuit = selectCircuit(inputs, outputs);
    const { vkey } = await fetchCircuitArtifacts(circuit.name, options);
    return await snarkjs.groth16.verify(vkey, publicSignals, proof);
  } catch (error) {
    throw new ProofError(
      "proof verification failed: " + toProofError(error).message,
    );
  }
}
