import type { AccountView } from "../account/account.js";
import { createIndexerClient } from "../clients/indexer.js";
import type {
  CommitmentRecord,
  IndexerNullifierRecord,
} from "../clients/indexer.js";
import { createServiceConfig } from "../config.js";
import { poseidon } from "../crypto/adapters/index.js";
import { decryptNote } from "../crypto/encrypt.js";
import { CoreError, InitializationError } from "../errors.js";
import { FieldSize, Hex } from "../keys/hex.js";
import {
  createMerkleTrees,
  hydrateChain,
  rebuildTreeFromStore,
  type NoteRecord,
} from "../state/index.js";
import { formatUint256, parseHexToBigInt } from "../utils/bigint.js";
import { ensureChainId } from "../utils/validators.js";
import type {
  Ciphertext,
  NoteSyncOptions,
  NoteSyncStateStore,
} from "./types/index.js";

const DEFAULT_BATCH_SIZE = 256;

export type { NoteSyncOptions, NoteSyncStateStore };

type ChainSyncStatus = {
  inFlight: boolean;
  lastSuccess: number | null;
  lastError?: string;
};

type AdapterCommitmentRecord = {
  index: number;
  commitment: string;
  txHash?: string;
  insertedAt?: number;
  eventType?: string;
  adapterNpk?: string;
  adapterToken?: string;
  adapterAmount?: string;
  adapterRandom?: string;
};

function buildCiphertext(
  ephemeralKey: string,
  bytes: [string, string, string],
): Ciphertext {
  return {
    ephemeralKey: parseHexToBigInt(ephemeralKey),
    data: [
      parseHexToBigInt(bytes[0]),
      parseHexToBigInt(bytes[1]),
      parseHexToBigInt(bytes[2]),
    ],
  };
}

function encodeCiphertext(ciphertext: Ciphertext): Uint8Array {
  // 4 fields: ephemeralKey + 3 data values
  const payload = new Uint8Array(FieldSize.SCALAR * 4);
  payload.set(Hex.toBytes(formatUint256(ciphertext.ephemeralKey)), 0);
  ciphertext.data.forEach((value, index) => {
    const start = (index + 1) * FieldSize.SCALAR;
    payload.set(Hex.toBytes(formatUint256(value)), start);
  });
  return payload;
}

export function createNoteSyncService(
  stateStore: NoteSyncStateStore,
  options: NoteSyncOptions = {},
) {
  const trees = options.merkleTrees ?? createMerkleTrees();
  const limit = options.limit ?? DEFAULT_BATCH_SIZE;
  const status = new Map<number, ChainSyncStatus>();
  const hydrated = new Set<number>();

  // Initialize indexer client
  let indexerClient = options.indexerClient;
  if (!indexerClient) {
    const fetchImpl =
      options.fetch ?? (typeof fetch === "function" ? fetch : undefined);
    if (!fetchImpl) {
      throw new InitializationError(
        "fetch dependency is required to sync indexer commitments",
      );
    }
    if (!options.gatewayUrl) {
      throw new InitializationError(
        "gatewayUrl is required to sync indexer commitments",
      );
    }
    const serviceConfig = createServiceConfig(options.gatewayUrl);
    indexerClient = createIndexerClient(serviceConfig.indexerBaseUrl, {
      fetch: fetchImpl,
    });
  }

  function createNoteRecord(params: {
    chainId: number;
    index: number;
    commitment: string;
    token: string;
    amount: bigint;
    npk: bigint;
    mpk: bigint;
    random: bigint;
    nullifier: string;
    createdTxHash?: string;
    createdEventType?: string;
    createdAt?: number;
    spentAt?: number;
    spentTxHash?: string;
  }): NoteRecord {
    const {
      chainId,
      index,
      commitment,
      token,
      amount,
      npk,
      mpk,
      random,
      nullifier,
      createdTxHash,
      createdEventType,
      createdAt,
      spentAt,
      spentTxHash,
    } = params;
    const base: NoteRecord = {
      chainId,
      index,
      token,
      value: amount.toString(),
      commitment,
      npk: formatUint256(npk),
      mpk: formatUint256(mpk),
      random: formatUint256(random),
      nullifier,
      createdTxHash,
      createdEventType,
      createdAt,
      spentTxHash,
    };
    return spentAt === undefined ? base : { ...base, spentAt };
  }

  // Try to reconstruct a note from an adapter deposit event.
  // Adapter deposits have zero ciphertext; the indexer returns npk, token, amount, random directly.
  function tryReconstructAdapterNote(
    chainId: number,
    record: AdapterCommitmentRecord,
    account: AccountView,
  ): NoteRecord | null {
    if (
      !record.adapterNpk ||
      !record.adapterToken ||
      !record.adapterAmount ||
      !record.adapterRandom
    ) {
      return null;
    }

    const eventNpk = parseHexToBigInt(record.adapterNpk);
    const eventRandom = parseHexToBigInt(record.adapterRandom);
    const eventAmount = parseHexToBigInt(record.adapterAmount);
    const eventToken = record.adapterToken.toLowerCase();

    // Check if npk matches this account: npk should equal poseidon([mpk, random])
    const derivedNpk = poseidon([account.masterPublicKey, eventRandom]);
    if (derivedNpk !== eventNpk) {
      return null;
    }

    // Verify commitment: poseidon([npk, uint160(token), amount])
    const commitment = poseidon([eventNpk, BigInt(eventToken), eventAmount]);
    if (commitment !== parseHexToBigInt(record.commitment)) {
      return null;
    }

    const nullifier = poseidon([account.nullifyingKey, BigInt(record.index)]);
    const nullifierHex = formatUint256(nullifier);

    return createNoteRecord({
      chainId,
      index: record.index,
      commitment: record.commitment,
      token: eventToken,
      amount: eventAmount,
      npk: eventNpk,
      mpk: account.masterPublicKey,
      random: eventRandom,
      nullifier: nullifierHex,
      createdTxHash: record.txHash,
      createdEventType: record.eventType,
      createdAt:
        record.insertedAt != null ? record.insertedAt * 1000 : undefined,
    });
  }

  // Try to decrypt a note. Returns the note record if successful, null otherwise.
  function tryDecryptNoteRecord(
    chainId: number,
    record: CommitmentRecord,
    account: AccountView,
  ): NoteRecord | null {
    // Adapter deposits have zero ciphertext — reconstruct from event fields
    if (record.eventType === "adapter_deposit") {
      return tryReconstructAdapterNote(chainId, record, account);
    }

    const ciphertext = buildCiphertext(record.ephemeralKey, record.ciphertext);
    // Withdrawal commitments have zero ephemeral key — not decryptable
    if (ciphertext.ephemeralKey === 0n) {
      return null;
    }
    let note;
    try {
      note = decryptNote(ciphertext, account.viewingKeyPair.privateKey);
    } catch (e: unknown) {
      // Trial decryption: expected to fail for notes not belonging to this account
      if (!(e instanceof Error)) throw e;
      return null;
    }
    const random = note.random;
    const amount = note.amount;
    const token = note.token;
    const npk = poseidon([account.masterPublicKey, random]);
    const commitment = poseidon([npk, BigInt(token), amount]);
    if (commitment !== parseHexToBigInt(record.commitment)) {
      return null;
    }

    const nullifier = poseidon([account.nullifyingKey, BigInt(record.index)]);
    const nullifierHex = formatUint256(nullifier);

    return createNoteRecord({
      chainId,
      index: record.index,
      commitment: record.commitment,
      token,
      amount,
      npk,
      mpk: account.masterPublicKey,
      random,
      nullifier: nullifierHex,
      createdTxHash: record.txHash,
      createdEventType: record.eventType,
      createdAt:
        record.insertedAt != null ? record.insertedAt * 1000 : undefined,
    });
  }

  // Pulls commitments from the indexer, updating local tree and notes atomically.
  // Uses batch nullifier check to avoid individual 404-generating queries.
  async function ingestFrom(
    chainId: number,
    start: number,
    account: AccountView,
  ) {
    let cursor = start;
    for (;;) {
      const batch = await indexerClient!.fetchCommitmentBatch({
        chainId,
        start: cursor,
        limit,
      });

      if (batch.commitments.length === 0) {
        break;
      }

      // Phase 1: Process commitments — add to tree + collect batch write items
      const decryptedNotes: NoteRecord[] = [];
      const batchItems: Array<
        Parameters<typeof stateStore.syncCommitmentBatch>[0][number]
      > = [];

      for (const record of batch.commitments) {
        const expectedIndex = trees.getLeafCount(chainId);
        if (record.index !== expectedIndex) {
          throw new CoreError(
            `indexed commitments out of order: expected index ${expectedIndex}, got ${record.index} (cursor=${cursor})`,
          );
        }

        const value = Hex.toBigInt(record.commitment);
        const { index } = trees.addLeaf(chainId, value);
        if (index !== record.index) {
          throw new CoreError("local merkle tree desynchronized");
        }

        const noteRecord = tryDecryptNoteRecord(chainId, record, account);
        const ciphertext = buildCiphertext(
          record.ephemeralKey,
          record.ciphertext,
        );
        const ciphertextBytes = encodeCiphertext(ciphertext);

        batchItems.push({
          leaf: {
            chainId,
            index: record.index,
            commitment: record.commitment,
            txHash: record.txHash,
            eventType: record.eventType,
            adapterNpk: record.adapterNpk,
            adapterToken: record.adapterToken,
            adapterAmount: record.adapterAmount,
            adapterRandom: record.adapterRandom,
            insertedAt: record.insertedAt,
          },
          ciphertext: {
            chainId,
            index: record.index,
            payload: ciphertextBytes,
          },
          root: { chainId, root: record.root },
          note: noteRecord ?? undefined,
        });

        if (noteRecord) {
          decryptedNotes.push(noteRecord);
        }

        cursor = record.index + 1;
      }

      // Flush all commitment writes in a single batch
      await stateStore.syncCommitmentBatch(batchItems);

      // Phase 2: Batch nullifier check for decrypted notes
      if (decryptedNotes.length > 0) {
        const notesToCheck: NoteRecord[] = [];
        for (const note of decryptedNotes) {
          const existing = await stateStore.getNote(chainId, note.index);
          if (existing?.spentAt !== undefined) {
            await stateStore.putNullifier({
              chainId,
              nullifier: note.nullifier,
              noteIndex: note.index,
            });
          } else {
            notesToCheck.push(note);
          }
        }

        if (notesToCheck.length > 0) {
          const spentNullifiers: IndexerNullifierRecord[] =
            await indexerClient!.checkNullifiers({
              chainId,
              nullifiers: notesToCheck.map((n) => n.nullifier),
            });
          const spentMap = new Map(
            spentNullifiers.map((n) => [n.nullifier, n]),
          );

          for (const note of notesToCheck) {
            const spent = spentMap.get(note.nullifier);
            if (spent) {
              const spentAtMs = spent.spentAt * 1000;
              await stateStore.putNullifier({
                chainId,
                nullifier: note.nullifier,
                noteIndex: note.index,
              });
              await stateStore.markNoteSpent(
                chainId,
                note.index,
                spentAtMs,
                spent.txHash,
              );
            }
          }
        }
      }
    }
  }

  // ── Tiered chain-state diagnosis ──────────────────────────────────────────
  //
  // Tier 1 (2 API calls): compare first + last local commitment against indexer.
  //   Both match → consistent (incremental sync).
  // Tier 2 (O(log N) API calls): binary search for the divergence point when
  //   the first commitment matches but the tail doesn't (e.g. reorg).
  // Tier 3 (1 API call): first commitment differs or indexer empty → full wipe.

  type SyncDiagnosis =
    | { kind: "consistent" }
    | { kind: "full-divergence" }
    | { kind: "partial-divergence"; validPrefix: number };

  async function diagnoseChainState(
    chainId: number,
    localCount: number,
  ): Promise<SyncDiagnosis> {
    // Tier 1: compare first commitment
    const firstBatch = await indexerClient!.fetchCommitmentBatch({
      chainId,
      start: 0,
      limit: 1,
    });
    const localFirst = await stateStore.getLeaf(chainId, 0);

    if (firstBatch.commitments.length === 0 || !localFirst) {
      return { kind: "full-divergence" };
    }
    if (firstBatch.commitments[0].commitment !== localFirst.commitment) {
      return { kind: "full-divergence" };
    }

    // Single-leaf shortcut: first matches and there's only one local leaf.
    if (localCount === 1) {
      return { kind: "consistent" };
    }

    // Compare last local commitment
    const lastBatch = await indexerClient!.fetchCommitmentBatch({
      chainId,
      start: localCount - 1,
      limit: 1,
    });
    const localLast = await stateStore.getLeaf(chainId, localCount - 1);

    if (
      lastBatch.commitments.length > 0 &&
      localLast &&
      lastBatch.commitments[0].commitment === localLast.commitment
    ) {
      return { kind: "consistent" };
    }

    // Tier 2: binary search for divergence point
    const divergePoint = await findDivergencePoint(chainId, 1, localCount - 1);
    return { kind: "partial-divergence", validPrefix: divergePoint };
  }

  async function findDivergencePoint(
    chainId: number,
    low: number,
    high: number,
  ): Promise<number> {
    while (low < high) {
      const mid = Math.floor((low + high) / 2);
      const batch = await indexerClient!.fetchCommitmentBatch({
        chainId,
        start: mid,
        limit: 1,
      });
      const localLeaf = await stateStore.getLeaf(chainId, mid);

      if (
        batch.commitments.length > 0 &&
        localLeaf &&
        batch.commitments[0].commitment === localLeaf.commitment
      ) {
        low = mid + 1;
      } else {
        high = mid;
      }
    }
    return low;
  }

  // Clears stale tail data and re-ingests from the divergence point.
  async function partialResync(
    chainId: number,
    fromIndex: number,
    account: AccountView,
  ) {
    hydrated.delete(chainId);
    await Promise.all([
      stateStore.clearChainDataFromIndex(chainId, fromIndex),
      stateStore.clearNullifiersFromIndex(chainId, fromIndex),
      stateStore.clearRescanCursors(chainId),
    ]);
    trees.reset(chainId);
    await rebuildTreeFromStore({
      chainId,
      trees,
      loadLeaves: stateStore.listLeaves.bind(stateStore),
    });
    hydrated.add(chainId);
    await ingestFrom(chainId, fromIndex, account);
  }

  // Clears local state for a chain and rehydrates fully from the indexer.
  async function fullResync(chainId: number, account: AccountView) {
    hydrated.delete(chainId);
    trees.reset(chainId);
    await Promise.all([
      stateStore.clearLeaves(chainId),
      stateStore.clearNotes(chainId),
      stateStore.clearCiphertexts(chainId),
      stateStore.clearNullifiers(chainId),
      stateStore.clearRescanCursors(chainId),
    ]);
    await ingestFrom(chainId, 0, account);
  }

  // Decode a stored ciphertext (4 x 32-byte values) into a Ciphertext object
  function decodeCiphertext(payload: Uint8Array): Ciphertext {
    const ephemeralKey = Hex.toBigInt(
      Hex.fromBytes(payload.slice(0, FieldSize.SCALAR)),
    );
    const data: bigint[] = [];
    for (let i = 0; i < 3; i++) {
      const start = (i + 1) * FieldSize.SCALAR;
      const end = start + FieldSize.SCALAR;
      const slice = payload.slice(start, end);
      data.push(Hex.toBigInt(Hex.fromBytes(slice)));
    }
    return { ephemeralKey, data: data as [bigint, bigint, bigint] };
  }

  // Re-scan stored ciphertexts for a new account, using batch nullifier checks.
  // Adapter deposits are reconstructed from locally cached event fields when available.
  async function rescanCiphertextsForAccount(
    chainId: number,
    account: AccountView,
    leafCount: number,
    fromIndex = 0,
  ) {
    const accountMpk = formatUint256(account.masterPublicKey);

    type PendingNote = {
      note: NoteRecord;
      baseParams: Parameters<typeof createNoteRecord>[0];
    };
    const pendingNotes: PendingNote[] = [];

    // Batch-load all data upfront instead of per-index awaits
    const [allNotes, allCiphertexts, allLeaves] = await Promise.all([
      stateStore.listNotes({ chainId, mpk: accountMpk }),
      stateStore.listCiphertexts(chainId),
      stateStore.listLeaves(chainId),
    ]);
    const noteSet = new Set(allNotes.map((n) => n.index));
    const ctMap = new Map(allCiphertexts.map((c) => [c.index, c.payload]));
    const leafMap = new Map(allLeaves.map((l) => [l.index, l]));
    const adapterRecords = new Map<number, AdapterCommitmentRecord>();
    const missingAdapterIndices: number[] = [];

    for (let index = fromIndex; index < leafCount; index++) {
      const leaf = leafMap.get(index);
      if (!leaf || leaf.eventType !== "adapter_deposit") continue;
      if (
        leaf.adapterNpk &&
        leaf.adapterToken &&
        leaf.adapterAmount &&
        leaf.adapterRandom
      ) {
        adapterRecords.set(index, {
          index,
          commitment: leaf.commitment,
          txHash: leaf.txHash,
          insertedAt: leaf.insertedAt,
          eventType: leaf.eventType ?? "adapter_deposit",
          adapterNpk: leaf.adapterNpk,
          adapterToken: leaf.adapterToken,
          adapterAmount: leaf.adapterAmount,
          adapterRandom: leaf.adapterRandom,
        });
      } else {
        missingAdapterIndices.push(index);
      }
    }

    if (missingAdapterIndices.length > 0) {
      const missingSet = new Set(missingAdapterIndices);
      const minIndex = missingAdapterIndices[0]!;
      const maxIndex = missingAdapterIndices[missingAdapterIndices.length - 1]!;
      let cursor = minIndex;

      while (cursor <= maxIndex && missingSet.size > 0) {
        const batch = await indexerClient!.fetchCommitmentBatch({
          chainId,
          start: cursor,
          limit,
        });
        if (batch.commitments.length === 0) break;
        for (const record of batch.commitments) {
          if (!missingSet.has(record.index)) continue;
          adapterRecords.set(record.index, record);
          missingSet.delete(record.index);
        }
        cursor = batch.commitments[batch.commitments.length - 1]!.index + 1;
      }
    }

    for (let index = fromIndex; index < leafCount; index++) {
      if (noteSet.has(index)) continue;

      const ciphertextBytes = ctMap.get(index);

      const leaf = leafMap.get(index);
      if (!leaf) continue;

      // Adapter deposits: reconstruct from cached metadata or batched indexer fallback
      if (leaf.eventType === "adapter_deposit") {
        const record = adapterRecords.get(index);
        if (record) {
          const adapterNote = tryReconstructAdapterNote(
            chainId,
            record,
            account,
          );
          if (adapterNote) {
            const baseParams = {
              chainId,
              index,
              commitment: record.commitment,
              token: adapterNote.token,
              amount: BigInt(adapterNote.value),
              npk: parseHexToBigInt(adapterNote.npk),
              mpk: account.masterPublicKey,
              random: parseHexToBigInt(adapterNote.random),
              nullifier: adapterNote.nullifier,
              createdTxHash: record.txHash || leaf.txHash,
              createdEventType: record.eventType || leaf.eventType,
              createdAt:
                record.insertedAt != null
                  ? record.insertedAt * 1000
                  : leaf.insertedAt != null
                    ? leaf.insertedAt * 1000
                    : undefined,
            };
            pendingNotes.push({ note: adapterNote, baseParams });
          }
        }
        continue;
      }

      if (!ciphertextBytes) continue;

      const ciphertext = decodeCiphertext(ciphertextBytes);
      // Withdrawal commitments have zero ephemeral key — not decryptable
      if (ciphertext.ephemeralKey === 0n) continue;
      let note;
      try {
        note = decryptNote(ciphertext, account.viewingKeyPair.privateKey);
      } catch (e: unknown) {
        // Trial decryption: expected to fail for notes not belonging to this account
        if (!(e instanceof Error)) throw e;
        continue;
      }

      const npk = poseidon([account.masterPublicKey, note.random]);
      const commitment = poseidon([npk, BigInt(note.token), note.amount]);
      if (commitment !== parseHexToBigInt(leaf.commitment)) continue;

      const nullifier = poseidon([account.nullifyingKey, BigInt(index)]);
      const nullifierHex = formatUint256(nullifier);

      const baseNoteParams = {
        chainId,
        index,
        commitment: leaf.commitment,
        token: note.token,
        amount: note.amount,
        npk,
        mpk: account.masterPublicKey,
        random: note.random,
        nullifier: nullifierHex,
        createdTxHash: leaf.txHash,
        createdEventType: leaf.eventType,
        createdAt: leaf.insertedAt != null ? leaf.insertedAt * 1000 : undefined,
      };

      pendingNotes.push({
        note: createNoteRecord(baseNoteParams),
        baseParams: baseNoteParams,
      });
    }

    if (pendingNotes.length > 0) {
      const spentNullifiers: IndexerNullifierRecord[] =
        await indexerClient!.checkNullifiers({
          chainId,
          nullifiers: pendingNotes.map((p) => p.note.nullifier),
        });
      const spentMap = new Map(spentNullifiers.map((n) => [n.nullifier, n]));

      for (const { note, baseParams } of pendingNotes) {
        const spent = spentMap.get(note.nullifier);
        if (spent) {
          await stateStore.putNullifier({
            chainId,
            nullifier: note.nullifier,
            noteIndex: note.index,
          });
          await stateStore.putNote(
            createNoteRecord({
              ...baseParams,
              spentAt: spent.spentAt * 1000,
              spentTxHash: spent.txHash,
            }),
          );
        } else {
          await stateStore.putNote(note);
        }
      }
    }
  }

  // Check existing unspent notes for nullification using batch check.
  async function checkExistingNotesForNullification(
    chainId: number,
    account: AccountView,
  ) {
    const accountMpk = formatUint256(account.masterPublicKey);
    const unspentNotes = await stateStore.listNotes({
      chainId,
      mpk: accountMpk,
      includeSpent: false,
    });

    if (unspentNotes.length === 0) return;

    const spentNullifiers: IndexerNullifierRecord[] =
      await indexerClient!.checkNullifiers({
        chainId,
        nullifiers: unspentNotes.map((n) => n.nullifier),
      });
    const spentMap = new Map(spentNullifiers.map((n) => [n.nullifier, n]));

    for (const note of unspentNotes) {
      const spent = spentMap.get(note.nullifier);
      if (spent) {
        await stateStore.putNullifier({
          chainId,
          nullifier: note.nullifier,
          noteIndex: note.index,
        });
        await stateStore.markNoteSpent(
          chainId,
          note.index,
          spent.spentAt * 1000,
          spent.txHash,
        );
      }
    }
  }

  /**
   * Syncs a single chain into local state, optionally forcing a full rebuild.
   */
  async function syncChain(
    chainId: number,
    account: AccountView,
    opts: { forceFullResync?: boolean } = {},
  ): Promise<void> {
    ensureChainId(chainId);
    const current = status.get(chainId) ?? {
      inFlight: false,
      lastSuccess: null,
    };
    if (current.inFlight) return;
    status.set(chainId, { ...current, inFlight: true, lastError: undefined });

    try {
      const start = opts.forceFullResync
        ? 0
        : await hydrateChain({
            chainId,
            trees,
            loadLeaves: stateStore.listLeaves.bind(stateStore),
            hydrated,
          });

      if (opts.forceFullResync) {
        await fullResync(chainId, account);
      } else if (start > 0) {
        try {
          const diagnosis = await diagnoseChainState(chainId, start);
          switch (diagnosis.kind) {
            case "consistent":
              try {
                await ingestFrom(chainId, start, account);
              } catch (err) {
                console.warn(
                  `[note-sync] incremental ingest failed for chain ${chainId}, falling back to full resync:`,
                  err,
                );
                await fullResync(chainId, account);
              }
              break;
            case "partial-divergence":
              await partialResync(chainId, diagnosis.validPrefix, account);
              break;
            case "full-divergence":
              await fullResync(chainId, account);
              break;
          }
        } catch (err) {
          console.warn(
            `[note-sync] chain diagnosis failed for chain ${chainId}, falling back to full resync:`,
            err,
          );
          await fullResync(chainId, account);
        }
      } else {
        // start === 0, fresh first sync
        try {
          await ingestFrom(chainId, 0, account);
        } catch (err) {
          console.warn(
            `[note-sync] initial ingest failed for chain ${chainId}, falling back to full resync:`,
            err,
          );
          await fullResync(chainId, account);
        }
      }

      // Rescan ciphertexts for multi-account support (only new leaves)
      const accountMpk = formatUint256(account.masterPublicKey);
      const leafCount = trees.getLeafCount(chainId);
      if (leafCount > 0 && !opts.forceFullResync) {
        const lastScanned = await stateStore.getRescanCursor(
          chainId,
          accountMpk,
        );
        if (lastScanned === null || lastScanned < leafCount) {
          await rescanCiphertextsForAccount(
            chainId,
            account,
            leafCount,
            lastScanned ?? 0,
          );
          await stateStore.setRescanCursor(chainId, accountMpk, leafCount);
        }
      }

      // Check if any existing unspent notes have been nullified
      await checkExistingNotesForNullification(chainId, account);

      status.set(chainId, { inFlight: false, lastSuccess: Date.now() });
    } catch (err) {
      status.set(chainId, {
        inFlight: false,
        lastSuccess: current.lastSuccess ?? null,
        lastError: err instanceof Error ? err.message : String(err),
      });
      throw err;
    }
  }

  /**
   * Syncs multiple chains sequentially.
   */
  async function syncChains(
    chainIds: number[],
    account: AccountView,
    opts?: { forceFullResync?: boolean },
  ): Promise<void> {
    for (const chainId of chainIds) {
      await syncChain(chainId, account, opts);
    }
  }

  function getStatus() {
    return status;
  }

  return {
    syncChain,
    syncChains,
    getStatus,
  };
}
