import ky, { TimeoutError } from "ky";

import { InitializationError } from "../errors.js";

export type FetchLike = (
  input: RequestInfo | URL,
  init?: RequestInit,
) => Promise<Response>;

/**
 * Resolve fetch implementation from options or global.
 * @param providedFetch - Optional fetch implementation
 * @returns Fetch function or undefined if not available
 */
export function resolveFetch(
  providedFetch?: FetchLike,
): typeof fetch | undefined {
  return providedFetch ?? (typeof fetch === "function" ? fetch : undefined);
}

export type JsonHttpDeps = { fetch: FetchLike };

export type JsonRequestOptions = {
  method: "GET" | "POST" | "PUT" | "PATCH" | "DELETE";
  path: string;
  query?: Record<string, string | number | boolean | undefined>;
  json?: unknown;
  body?: BodyInit;
  headers?: HeadersInit;
  signal?: AbortSignal;
};

export type JsonHttpClient = {
  request<T>(opts: JsonRequestOptions): Promise<T>;
};

export class HttpError extends Error {
  readonly status: number;
  readonly body: unknown;

  constructor(message: string, status: number, body: unknown) {
    super(message);
    this.status = status;
    this.body = body;
  }
}

async function readErrorBodySafe(res: Response) {
  try {
    return await res.clone().json();
  } catch {
    const text = await res.text();
    return text || null;
  }
}

export function createJsonHttpClient(
  baseUrl: string,
  deps: JsonHttpDeps,
): JsonHttpClient {
  if (!baseUrl) throw new InitializationError("baseUrl is required");
  if (!deps?.fetch) throw new InitializationError("deps.fetch is required");

  // Ensure `fetch` is invoked with a global `this` to avoid "Illegal invocation"
  // errors in some browser environments when the function is extracted. // TODO: can we fix this in another way?
  const fetchImpl: FetchLike = (...args) => deps.fetch.apply(globalThis, args);

  const api = ky.create({
    prefixUrl: baseUrl.replace(/\/+$/, ""),
    fetch: fetchImpl,
    // Disable ky's automatic error throwing to prevent browser DevTools
    // from logging expected 404s as network errors
    throwHttpErrors: false,
    retry: 0,
  });

  const RETRYABLE_STATUSES = [502, 503, 504];
  const MAX_RETRIES = 3;
  const BASE_DELAY_MS = 500;

  return {
    async request<T>(opts: JsonRequestOptions): Promise<T> {
      let res!: Response;

      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
          res = await api(opts.path.replace(/^\//, ""), {
            method: opts.method,
            searchParams: opts.query,
            json: opts.json,
            body: opts.body,
            headers: opts.headers,
            signal: opts.signal,
          });
        } catch (err) {
          // Only network-level errors reach here (timeout, connection refused, etc.)
          if (err instanceof TimeoutError) {
            throw new HttpError("HTTP timeout", 408, null);
          }
          throw new HttpError(
            err instanceof Error ? err.message : "Network error",
            0,
            null,
          );
        }

        if (RETRYABLE_STATUSES.includes(res.status) && attempt < MAX_RETRIES) {
          const delay = BASE_DELAY_MS * 2 ** attempt + Math.random() * 200;
          await new Promise((r) => setTimeout(r, delay));
          continue;
        }
        break;
      }

      // HTTP status errors handled outside try-catch - no redundant catch/rethrow
      if (!res.ok) {
        const body = await readErrorBodySafe(res);
        throw new HttpError(
          `HTTP ${res.status} ${res.statusText}`.trim(),
          res.status,
          body,
        );
      }

      return (await res.json()) as T;
    },
  };
}
