/**
 * Configuration for the prover system.
 * Handles artifact loading from Cloudflare R2 or local files
 * in Node.js development/test environments.
 */

export const DEFAULT_ARTIFACT_BASE_URL = "https://artifacts.unlink.xyz";

/**
 * Artifact file types.
 */
export enum ArtifactType {
  WASM = "joinsplit.wasm",
  ZKEY = "joinsplit.zkey",
  VKEY = "joinsplit.vkey.json",
}

/**
 * Artifact source configuration.
 */
export interface ArtifactSourceConfig {
  /**
   * Base URL for artifact hosting.
   * Defaults to Cloudflare R2 CDN domain.
   */
  readonly baseUrl?: string;
  /**
   * Artifact version path segment.
   * Must be a pinned immutable version like `vabc12345` for remote mode.
   * Optional only when using local-only mode (`preferLocalFiles: true`).
   */
  readonly version?: string;
  /**
   * Node.js-only override to load local artifacts first.
   */
  readonly preferLocalFiles?: boolean;
}

/**
 * Fully-resolved artifact source configuration.
 */
export interface ResolvedArtifactSourceConfig {
  readonly baseUrl: string;
  readonly version?: string;
  readonly preferLocalFiles: boolean;
}

export interface RemoteArtifactSourceConfig {
  readonly baseUrl: string;
  readonly version: string;
}

const ARTIFACT_VERSION_SEGMENT_PATTERN = /^[A-Za-z0-9._-]+$/;

export function assertValidArtifactVersion(
  version: string,
  label = "artifactSource.version",
): void {
  if (version.toLowerCase() === "latest") {
    throw new Error(`${label} must be an immutable version, not 'latest'`);
  }
  if (
    version === "." ||
    version === ".." ||
    version.includes("..") ||
    !ARTIFACT_VERSION_SEGMENT_PATTERN.test(version)
  ) {
    throw new Error(
      `${label} must be a safe single path segment using [A-Za-z0-9._-] and must not contain '..'`,
    );
  }
}

/**
 * Resolve artifact source configuration with defaults.
 */
export function resolveArtifactSourceConfig(
  config?: ArtifactSourceConfig,
): ResolvedArtifactSourceConfig {
  const baseUrl = (config?.baseUrl ?? DEFAULT_ARTIFACT_BASE_URL).replace(
    /\/+$/,
    "",
  );
  const rawVersion = config?.version;
  const version =
    rawVersion === undefined
      ? undefined
      : rawVersion.replace(/^\/+|\/+$/g, "").trim();
  const preferLocalFiles = config?.preferLocalFiles ?? false;

  if (version === "") {
    throw new Error("artifactSource.version must be a non-empty string");
  }
  if (version) {
    assertValidArtifactVersion(version);
  }
  if (!version && !preferLocalFiles) {
    throw new Error(
      "artifactSource.version is required unless artifactSource.preferLocalFiles is true",
    );
  }

  return {
    baseUrl,
    version,
    preferLocalFiles,
  };
}

/**
 * Require a remote-capable source (baseUrl + immutable version).
 */
export function requireRemoteArtifactSource(
  source: ResolvedArtifactSourceConfig,
): RemoteArtifactSourceConfig {
  if (!source.version) {
    throw new Error(
      "artifactSource.version is required when loading remote artifacts",
    );
  }
  return {
    baseUrl: source.baseUrl,
    version: source.version,
  };
}

/**
 * Build R2 artifact URL for a given circuit and artifact type.
 * Format: `https://artifacts.unlink.xyz/<version>/<circuit>/<file>`.
 */
export function buildR2ArtifactUrl(
  circuitName: string,
  artifactType: ArtifactType,
  source: RemoteArtifactSourceConfig,
): string {
  return `${source.baseUrl}/${source.version}/${circuitName}/${artifactType}`;
}

/**
 * Build R2 checksums manifest URL for a given circuit.
 * Format: `https://artifacts.unlink.xyz/<version>/<circuit>/checksums.json`.
 */
export function buildR2ChecksumsUrl(
  circuitName: string,
  source: RemoteArtifactSourceConfig,
): string {
  return `${source.baseUrl}/${source.version}/${circuitName}/checksums.json`;
}

/**
 * Get relative path for local artifact loading
 * Used in Node.js environment when artifacts are bundled
 * @param circuitName Full circuit name (e.g., "joinsplit_2x3_16")
 * @param artifactType Type of artifact
 * @returns Relative path to artifact
 */
export function getLocalArtifactPath(
  circuitName: string,
  artifactType: ArtifactType,
): string[] {
  // Return multiple candidate paths for different build scenarios
  return [
    // When compiled: dist/prover/ -> ../../artifacts/circuits/{circuit}/
    `../../artifacts/circuits/${circuitName}/${artifactType}`,
    // When in source: prover/ -> ../artifacts/circuits/{circuit}/
    `../artifacts/circuits/${circuitName}/${artifactType}`,
  ];
}

/**
 * Runtime detection utilities
 */
export const Runtime = {
  /**
   * Check if running in browser environment
   */
  isBrowser(): boolean {
    return typeof window !== "undefined" && typeof document !== "undefined";
  },

  /**
   * Check if running in Node.js environment
   */
  isNode(): boolean {
    return (
      typeof process !== "undefined" &&
      process.versions != null &&
      process.versions.node != null
    );
  },

  /**
   * Get environment description for debugging
   */
  getEnvironment(): string {
    if (this.isBrowser()) return "browser";
    if (this.isNode()) return "node";
    return "unknown";
  },
};
