import type { JobStatus } from "./state/index.js";

export class CoreError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CoreError";
  }
}

export class KeyValidationError extends CoreError {
  constructor(message: string) {
    super(message);
    this.name = "KeyValidationError";
  }
}

export class SchemaMismatchError extends CoreError {
  constructor(current: number, expected: number) {
    super(`schema mismatch (current ${current}, expected ${expected})`);
    this.name = "SchemaMismatchError";
  }
}

export class ValidationError extends CoreError {
  constructor(message: string) {
    super(message);
    this.name = "ValidationError";
  }
}

export class ProofError extends CoreError {
  constructor(message: string) {
    super(message);
    this.name = "ProofError";
  }
}

export class InitializationError extends CoreError {
  constructor(message: string) {
    super(message);
    this.name = "InitializationError";
  }
}

export class ReconcileError extends CoreError {
  public readonly status: JobStatus;
  constructor(message: string, status: JobStatus) {
    super(message);
    this.name = "ReconcileError";
    this.status = status;
  }
}

export class AdapterError extends CoreError {
  constructor(message: string) {
    super(message);
    this.name = "AdapterError";
  }
}
