export const TRANSACT_ABI =
  "function transact(((uint256[2] pA, uint256[2][2] pB, uint256[2] pC) proof, uint256 merkleRoot, uint256[] nullifierHashes, uint256[] newCommitments, (uint64 chainId, address poolAddress, uint256 adapterDataHash) context, (uint256 npk, uint256 amount, address token) withdrawal, (uint256 ephemeralKey, uint256[3] data)[] ciphertexts)[] _transactions)";

/** Default timeout for proof generation in milliseconds (60 seconds) */
export const DEFAULT_PROOF_TIMEOUT_MS = 60_000;

const transactInterface = new Interface([TRANSACT_ABI]);
const DEFAULT_WITHDRAWAL = {
  npk: 0n,
  amount: 0n,
  token: "0x0000000000000000000000000000000000000000",
};

export function computeBoundParamsHash(
  chainId: number,
  poolAddress: string,
  adapterDataHash: bigint = 0n,
): bigint {
  const coder = AbiCoder.defaultAbiCoder();
  const encoded = coder.encode(
    ["uint64", "uint160", "uint256"],
    [BigInt(chainId), BigInt(poolAddress), adapterDataHash],
  );
  return parseHexToBigInt(keccak256(encoded)) % SNARK_SCALAR_FIELD;
}

export type AdapterExecutionCall = {
  to: string;
  data: string;
  value: bigint;
};

export type AdapterExecutionReshield = {
  npk: bigint;
  random: bigint;
  token: string;
  minAmount: bigint;
};

export function computeAdapterDataHash(params: {
  calls: AdapterExecutionCall[];
  reshields: AdapterExecutionReshield[];
  inputTokens: string[];
  nonce: bigint;
  deadline: bigint;
  chainId: number;
}): bigint {
  const coder = AbiCoder.defaultAbiCoder();
  const encoded = coder.encode(
    [
      "tuple(address to, bytes data, uint256 value)[]",
      "tuple(uint256 npk, uint256 random, address token, uint256 minAmount)[]",
      "address[]",
      "uint256",
      "uint256",
      "uint256",
    ],
    [
      params.calls,
      params.reshields,
      params.inputTokens,
      params.nonce,
      params.deadline,
      BigInt(params.chainId),
    ],
  );
  return parseHexToBigInt(keccak256(encoded)) % SNARK_SCALAR_FIELD;
}

export function serializeWitness(
  proof: IMTMerkleProof,
  index: number,
): SerializedWitness {
  return {
    root: formatUint256(BigInt(proof.root)),
    leaf: formatUint256(BigInt(proof.leaf)),
    pathElements: proof.siblings.map((level: unknown[]) =>
      level.map((node: unknown) => formatUint256(BigInt(node as bigint))),
    ),
    pathIndices: proof.pathIndices ?? [],
    leafIndex: index,
  };
}

export function deserializeWitness(s: SerializedWitness): IMTMerkleProof {
  return {
    root: parseHexToBigInt(s.root),
    leaf: parseHexToBigInt(s.leaf),
    siblings: s.pathElements.map((level) => level.map(parseHexToBigInt)),
    pathIndices: s.pathIndices,
    leafIndex: s.leafIndex,
  };
}

// ============================================================================
// Internal: Single transaction proof generation
// ============================================================================

type SingleTxResult = {
  proof: Proof;
  witnesses: IMTMerkleProof[];
  nullifiers: string[];
  predictedCommitments: string[];
  merkleRoot: string;
  token: string;
  withdrawal: typeof DEFAULT_WITHDRAWAL;
  ciphertexts: { data: [bigint, bigint, bigint] }[];
  contexts: Array<{
    index: number;
    nullifier: bigint;
    nullifierHex: string;
    witness: IMTMerkleProof;
  }>;
  outputs: Array<{ value: bigint; hex: string; index: number }>;
  inputNotes: Array<{ value: string | bigint; random: string | bigint }>;
};

/**
 * Build proof for a single transaction item.
 * This is the core proof generation logic extracted for parallelization.
 */
async function buildSingleTransactionProof(
  store: TransactStateStore,
  account: AccountView,
  signer: Signer,
  chainId: number,
  poolAddress: string,
  tx: TransactItem,
  trees: ReturnType<typeof resolveMerkleTrees>,
  baseIndex: number,
  opts: ServiceOptions,
): Promise<SingleTxResult> {
  if (!tx.inputs?.length)
    throw new ValidationError("at least one input note is required");

  // Build input contexts (witnesses + nullifiers)
  const contexts: {
    index: number;
    nullifier: bigint;
    nullifierHex: string;
    witness: IMTMerkleProof;
  }[] = [];
  let merkleRoot: string | undefined;

  for (const input of tx.inputs) {
    const note = await store.getNote(chainId, input.index);
    if (!note) throw new ValidationError(`note ${input.index} not found`);
    if (note.spentAt !== undefined)
      throw new ValidationError(`note ${input.index} already spent`);

    const tree = trees.getOrCreate(chainId);
    if (input.index >= tree.getLeafCount())
      throw new ValidationError(`note ${input.index} out of range`);

    const witness = tree.createMerkleProof(input.index);
    const root = formatUint256(BigInt(witness.root));
    if (merkleRoot && merkleRoot !== root)
      throw new ValidationError("inputs must share same merkle root");
    merkleRoot = root;

    const nullifier = poseidon([account.nullifyingKey, BigInt(input.index)]);
    contexts.push({
      index: input.index,
      nullifier,
      nullifierHex: formatUint256(nullifier),
      witness,
    });
  }

  // Compute output commitments for regular notes
  const outputs = tx.outputs.map((o, i) => {
    const commitment = deriveCommitment({
      npk: poseidon([o.mpk, o.random]),
      amount: o.amount,
      token: o.token,
    });
    return {
      value: commitment,
      hex: formatUint256(commitment),
      index: baseIndex + i,
    };
  });

  // Handle withdrawal
  const withdrawal = tx.withdrawal ?? DEFAULT_WITHDRAWAL;
  const hasWithdrawal = withdrawal.amount > 0n;

  if (hasWithdrawal && withdrawal.token !== tx.token) {
    throw new ValidationError("Withdrawal token must match transaction token");
  }

  const withdrawalCommitment = hasWithdrawal
    ? deriveCommitment({
        npk: withdrawal.npk,
        amount: withdrawal.amount,
        token: withdrawal.token,
      })
    : null;

  // Build arrays for circuit
  const allCommitmentsOut = hasWithdrawal
    ? [...outputs.map((o) => o.value), withdrawalCommitment!]
    : outputs.map((o) => o.value);

  const allNpkOut = hasWithdrawal
    ? [...tx.outputs.map((o) => poseidon([o.mpk, o.random])), withdrawal.npk]
    : tx.outputs.map((o) => poseidon([o.mpk, o.random]));

  const allValueOut = hasWithdrawal
    ? [...tx.outputs.map((o) => o.amount), withdrawal.amount]
    : tx.outputs.map((o) => o.amount);

  // Build prover input
  const adapterDataHash = tx.adapterDataHash ?? 0n;
  const boundParams = computeBoundParamsHash(
    chainId,
    poolAddress,
    adapterDataHash,
  );
  const pubSignals = [
    parseHexToBigInt(merkleRoot!),
    boundParams,
    ...contexts.map((c) => c.nullifier),
    ...allCommitmentsOut,
  ];

  const inputNotes = await Promise.all(
    tx.inputs.map((i) => store.getNote(chainId, i.index).then((n) => n!)),
  );

  const sig = await signer.sign(poseidon(pubSignals));

  const proofInput: JoinsplitProofInput = {
    merkleRoot: parseHexToBigInt(merkleRoot!),
    boundParamsHash: boundParams,
    nullifiers: contexts.map((c) => c.nullifier),
    commitmentsOut: allCommitmentsOut,
    token: BigInt(tx.token),
    publicKey: signer.publicKey,
    signature: [sig.R8[0], sig.R8[1], sig.S],
    randomIn: inputNotes.map((n) => BigInt(n.random)),
    valueIn: inputNotes.map((n) => BigInt(n.value)),
    pathElements: contexts.map((c) =>
      c.witness.siblings.map((level) => level.map((s: bigint) => s)),
    ),
    leavesIndices: contexts.map((c) => BigInt(c.index)),
    nullifyingKey: account.nullifyingKey,
    npkOut: allNpkOut,
    valueOut: allValueOut,
  };

  const proofTimeoutMs = opts.proofTimeoutMs ?? DEFAULT_PROOF_TIMEOUT_MS;
  const proverOptions: ProverOptions = {
    ...opts.prover,
  };

  const txProof = await withTimeout(
    proveTransaction(proofInput, proverOptions),
    proofTimeoutMs,
    new ProofError(`Proof generation timed out after ${proofTimeoutMs}ms`),
  ).catch((e) => {
    if (e instanceof ProofError) throw e;
    throw new ProofError(`Proof generation failed: ${e.message}`);
  });

  const proof: Proof = {
    pA: [BigInt(txProof.proof.pi_a[0]!), BigInt(txProof.proof.pi_a[1]!)],
    pB: [
      [BigInt(txProof.proof.pi_b[0]![1]!), BigInt(txProof.proof.pi_b[0]![0]!)],
      [BigInt(txProof.proof.pi_b[1]![1]!), BigInt(txProof.proof.pi_b[1]![0]!)],
    ],
    pC: [BigInt(txProof.proof.pi_c[0]!), BigInt(txProof.proof.pi_c[1]!)],
    pubSignals,
  };

  return {
    proof,
    witnesses: contexts.map((c) => c.witness),
    nullifiers: contexts.map((c) => c.nullifierHex),
    predictedCommitments: outputs.map((o) => o.hex),
    merkleRoot: merkleRoot!,
    token: tx.token,
    withdrawal,
    ciphertexts: tx.outputs.map((note) => {
      const encrypted = encryptNote(note, note.viewingPublicKey);
      return { ephemeralKey: encrypted.ephemeralKey, data: encrypted.data };
    }),
    contexts,
    outputs,
    inputNotes,
  };
}

