import type { Account, AccountView, Signer } from "../account/account.js";
import { formatUint256 } from "../account/serialization.js";
import type { createBroadcasterClient } from "../clients/broadcaster.js";
import { ETH_TOKEN } from "../constants.js";
import { poseidon } from "../crypto/adapters/index.js";
import { AdapterError } from "../errors.js";
import { DEFAULT_JOB_TIMEOUT_MS } from "../state/store/jobs.js";
import { encodeAdapterExecute } from "../transactions/adapter.js";
import {
  computeAdapterDataHash,
  transact,
  type AdapterExecutionCall,
  type AdapterExecutionReshield,
} from "../transactions/transact.js";
import type {
  ServiceOptions,
  TransactRelayResult,
  TransactStateStore,
} from "../transactions/types/index.js";
import { planWithdrawals } from "../transactions/withdrawal-planner.js";
import { generateRelayId, randomBigint } from "../utils/random.js";
import {
  ensureAddress,
  ensureChainId,
  SNARK_SCALAR_FIELD,
} from "../utils/validators.js";
import type {
  InteractResult,
  ReceiveInput,
  SignerOverride,
  SpendInput,
  WalletInteractAPI,
  WalletInteractParams,
} from "./types.js";

const DEFAULT_DEADLINE_WINDOW_SECONDS = 600n;
const HEX_DATA_REGEX = /^0x[0-9a-fA-F]*$/;

type BroadcasterClient = Pick<
  ReturnType<typeof createBroadcasterClient>,
  "submitRelay"
>;

type NormalizedInputTokenSpec = {
  token: `0x${string}`;
  amount: bigint;
};

export type AdapterServiceDeps = {
  stateStore: TransactStateStore;
  txOpts: ServiceOptions;
  broadcasterClient: BroadcasterClient;
  requireActiveAccount: () => Promise<Account>;
  requireSigner: (account: AccountView) => Signer;
  planWithdrawalsFn?: typeof planWithdrawals;
  transactFn?: typeof transact;
  randomBigintFn?: () => bigint;
  nowFn?: () => number;
};

function ensureHexData(label: string, value: string): string {
  if (
    typeof value !== "string" ||
    !HEX_DATA_REGEX.test(value) ||
    value.length % 2 !== 0
  ) {
    throw new AdapterError(`${label} must be 0x-prefixed even-length hex data`);
  }
  return value;
}

function normalizeCall(
  call: AdapterExecutionCall,
  index: number,
): AdapterExecutionCall {
  const to = ensureAddress(`calls[${index}].to`, call.to);
  const data = ensureHexData(`calls[${index}].data`, call.data);
  if (call.value < 0n) {
    throw new AdapterError(`calls[${index}].value must be non-negative`);
  }

  return {
    to,
    data,
    value: call.value,
  };
}

function normalizeSpendInput(
  input: SpendInput,
  index: number,
): NormalizedInputTokenSpec {
  const token = ensureAddress(`spend[${index}].token`, input.token);
  if (token.toLowerCase() === ETH_TOKEN.toLowerCase()) {
    throw new AdapterError(
      `spend[${index}].token: native ETH is not supported in adapter execution`,
    );
  }
  if (input.amount <= 0n) {
    throw new AdapterError(`spend[${index}].amount must be greater than zero`);
  }

  return {
    token,
    amount: input.amount,
  };
}

function normalizeReceiveInput(
  receive: ReceiveInput,
  index: number,
): ReceiveInput {
  const token = ensureAddress(`receive[${index}].token`, receive.token);
  if (token.toLowerCase() === ETH_TOKEN.toLowerCase()) {
    throw new AdapterError(
      `receive[${index}].token: native ETH is not supported in adapter execution`,
    );
  }
  if (receive.minAmount < 0n) {
    throw new AdapterError(`receive[${index}].minAmount must be non-negative`);
  }

  return {
    token,
    minAmount: receive.minAmount,
  };
}

function randomFieldElement(randomBigintFn: () => bigint): bigint {
  const value = randomBigintFn() % SNARK_SCALAR_FIELD;
  return value < 0n ? value + SNARK_SCALAR_FIELD : value;
}

export function createAdapterService(
  deps: AdapterServiceDeps,
): WalletInteractAPI {
  const planWithdrawalsImpl = deps.planWithdrawalsFn ?? planWithdrawals;
  const transactImpl = deps.transactFn ?? transact;
  const randomBigintImpl = deps.randomBigintFn ?? randomBigint;
  const nowImpl = deps.nowFn ?? Date.now;

  return {
    async execute(
      params: WalletInteractParams,
      opts?: { skipBroadcast?: boolean },
      overrides?: SignerOverride,
    ): Promise<InteractResult> {
      ensureChainId(params.chainId);
      const poolAddress = ensureAddress("poolAddress", params.poolAddress);
      const adapterAddress = ensureAddress(
        "adapterAddress",
        params.adapterAddress,
      );

      if (!params.spend.length) {
        throw new AdapterError("at least one spend token is required");
      }
      if (!params.calls.length) {
        throw new AdapterError("at least one adapter call is required");
      }
      if (!params.receive.length) {
        throw new AdapterError("at least one receive output is required");
      }

      const spendInputs = params.spend.map((input, i) =>
        normalizeSpendInput(input, i),
      );

      const seenTokens = new Set<string>();
      for (const input of spendInputs) {
        const lower = input.token.toLowerCase();
        if (seenTokens.has(lower)) {
          throw new AdapterError(
            `duplicate spend token ${input.token}; combine amounts per token instead`,
          );
        }
        seenTokens.add(lower);
      }

      const calls = params.calls.map((call, i) => normalizeCall(call, i));
      const receiveSpecs = params.receive.map((receive, i) =>
        normalizeReceiveInput(receive, i),
      );

      const seenReceiveTokens = new Set<string>();
      for (const r of receiveSpecs) {
        const lower = r.token.toLowerCase();
        if (seenReceiveTokens.has(lower)) {
          throw new AdapterError(
            `duplicate receive token ${r.token}; each receive must target a unique token`,
          );
        }
        seenReceiveTokens.add(lower);
      }

      const account = overrides?.account ?? (await deps.requireActiveAccount());
      const signer = overrides?.signer ?? deps.requireSigner(account);
      const nowSeconds = BigInt(Math.floor(nowImpl() / 1000));
      const deadline =
        params.deadline ?? nowSeconds + DEFAULT_DEADLINE_WINDOW_SECONDS;
      if (deadline <= nowSeconds) {
        throw new AdapterError("deadline must be in the future");
      }

      const executionCalls = calls;

      const reshields: AdapterExecutionReshield[] = receiveSpecs.map(
        (receive) => {
          const random = randomFieldElement(randomBigintImpl);
          const npk = poseidon([account.masterPublicKey, random]);
          return {
            npk,
            random,
            token: receive.token,
            minAmount: receive.minAmount,
          };
        },
      );

      const inputTokens = spendInputs.map((input) => input.token);
      const nonce = randomFieldElement(randomBigintImpl);
      const adapterDataHash = computeAdapterDataHash({
        calls: executionCalls,
        reshields,
        inputTokens,
        nonce,
        deadline,
        chainId: params.chainId,
      });

      const notes = await deps.stateStore.listNotes({
        chainId: params.chainId,
        mpk: formatUint256(account.masterPublicKey),
        includeSpent: false,
      });

      const withdrawalPlans = planWithdrawalsImpl(
        notes,
        spendInputs.map((input) => ({
          token: input.token,
          amount: input.amount,
          recipient: adapterAddress,
        })),
        account.masterPublicKey,
        account.viewingKeyPair.pubkey,
      );

      const transactResult: TransactRelayResult = await transactImpl(
        deps.stateStore,
        {
          account,
          signer,
          chainId: params.chainId,
          poolAddress,
          transactions: withdrawalPlans.map((plan) => ({
            token: plan.token,
            inputs: plan.inputs.map((note) => ({ index: note.index })),
            outputs: plan.outputNotes,
            withdrawal: plan.withdrawal,
            adapterDataHash,
          })),
        },
        {
          ...deps.txOpts,
          skipBroadcast: true,
          persistJob: false,
        },
      );

      const adapterCalldata = encodeAdapterExecute({
        transactCalldata: transactResult.calldata,
        calls: executionCalls,
        reshields,
        inputTokens,
        nonce,
        deadline,
      });

      if (opts?.skipBroadcast) {
        return {
          relayId: transactResult.relayId,
          adapterCalldata,
          transactCalldata: transactResult.calldata,
          transactResult,
          reshields,
        };
      }

      const relayId = generateRelayId("adapter");
      const submission = await deps.broadcasterClient.submitRelay({
        clientTxId: relayId,
        chainId: params.chainId,
        payload: {
          kind: "call_data",
          to: adapterAddress,
          data: adapterCalldata,
        },
      });

      if (!submission.accepted) {
        throw new AdapterError(submission.message ?? "broadcaster rejected");
      }

      await deps.stateStore.putJob({
        relayId,
        kind: "adapter",
        chainId: params.chainId,
        mpk: formatUint256(account.masterPublicKey),
        status: "broadcasting",
        txHash: null,
        createdAt: nowImpl(),
        timeoutMs: DEFAULT_JOB_TIMEOUT_MS,
        poolAddress,
        calldata: transactResult.calldata,
        transactions: withdrawalPlans.map((plan, i) => ({
          token: plan.token,
          nullifiers: transactResult.transactions[i]?.nullifiers ?? [],
          predictedCommitments: (
            transactResult.transactions[i]?.predictedCommitments ?? []
          ).map((hex) => ({ hex })),
          withdrawal: {
            amount: plan.withdrawal.amount.toString(),
            recipient: adapterAddress,
          },
        })),
        adapterAddress,
        adapterCalldata,
        historyPreview: {
          kind: "Withdraw",
          amounts: spendInputs.map((input) => ({
            token: input.token,
            delta: (-input.amount).toString(),
          })),
        },
      });

      return {
        relayId,
        adapterCalldata,
        transactCalldata: transactResult.calldata,
        transactResult,
        reshields,
      };
    },
  };
}
