/**
 * Crypto adapters for browser-compatible cryptographic operations.
 *
 * Exports:
 * - poseidon: Poseidon hash via poseidon-lite (circomlib-compatible)
 * - deriveSpendingPublicKey, signMessage, verifySignature: EdDSA from @zk-kit/eddsa-poseidon
 */

// Polyfill must be the first import
import "./polyfills.js";

import {
  poseidon1,
  poseidon2,
  poseidon3,
  poseidon4,
  poseidon5,
  poseidon6,
  poseidon7,
  poseidon8,
  poseidon9,
  poseidon10,
  poseidon11,
  poseidon12,
  poseidon13,
  poseidon14,
  poseidon15,
  poseidon16,
} from "poseidon-lite";

type PoseidonFn = (inputs: (bigint | number | string)[]) => bigint;

// Index 0 unused — fns[n] handles n inputs
const fns: (PoseidonFn | undefined)[] = [
  undefined,
  poseidon1,
  poseidon2,
  poseidon3,
  poseidon4,
  poseidon5,
  poseidon6,
  poseidon7,
  poseidon8,
  poseidon9,
  poseidon10,
  poseidon11,
  poseidon12,
  poseidon13,
  poseidon14,
  poseidon15,
  poseidon16,
];

/**
 * Poseidon hash for arbitrary-length inputs, compatible with circomlib circuits.
 * - Arity 1-16: native poseidon-lite (matches circomlib exactly)
 * - Arity >16: sponge-style chaining — first 16 elements hashed natively,
 *   then remaining absorbed in chunks of 15 with running accumulator
 */
export function poseidon(inputs: (bigint | number)[]): bigint {
  const n = inputs.length;
  if (n === 0) throw new Error("Poseidon: empty input");
  if (n <= 16) return fns[n]!(inputs);

  // Chain: hash first 16, then absorb remaining in chunks of 15
  let acc = poseidon16(inputs.slice(0, 16));
  let i = 16;
  while (i < n) {
    const chunk = inputs.slice(i, i + 15);
    acc = fns[chunk.length + 1]!([acc, ...chunk]);
    i += 15;
  }
  return acc;
}

export {
  derivePublicKey as deriveSpendingPublicKey,
  signMessage,
  verifySignature,
} from "@zk-kit/eddsa-poseidon";
