import { zeroize } from "../crypto/secure-memory.js";
import { ValidationError } from "../errors.js";
import { encodeAddress } from "../keys/address.js";
import {
  deriveAccountKeys,
  type SpendingKeyPair,
  type ViewingKeyPair,
} from "../keys/derive.js";
import { Hex } from "../keys/hex.js";
import { Mnemonic } from "../keys/mnemonic.js";
import type { Storage } from "../types.js";
import { signTransactMessage } from "../utils/signature.js";

export type MasterSeedCrypto = {
  encrypt(seed: Uint8Array): Promise<Uint8Array> | Uint8Array;
  decrypt(payload: Uint8Array): Promise<Uint8Array> | Uint8Array;
};

export type GenerateMasterSeedOptions = {
  storage: Storage;
  rng: (n: number) => Uint8Array;
  crypto?: MasterSeedCrypto;
  overwrite?: boolean;
  mnemonicPassphrase: string;
};

export const MASTER_SEED_LENGTH = 64;
export const MASTER_SEED_KEY = "cfg:wallet:master_seed/v1";
export const MASTER_MNEMONIC_KEY = "cfg:wallet:master_mnemonic/v1";

const MNEMONIC_ENTROPY_BYTES = 32;

const textEncoder = new TextEncoder();
const textDecoder = new TextDecoder();

export type Account = {
  spendingKeyPair: SpendingKeyPair;
  viewingKeyPair: ViewingKeyPair;
  nullifyingKey: bigint;
  masterPublicKey: bigint;
  /** Bech32m address (unlink1...) for this account */
  address: string;
};

/**
 * Read-only account identity — the fields needed by the transaction layer
 * without any signing capability. Both Account and MultisigAccount satisfy this.
 */
export type AccountView = {
  nullifyingKey: bigint;
  masterPublicKey: bigint;
  viewingKeyPair: ViewingKeyPair;
  address: string;
};

/**
 * Signing capability decoupled from account identity.
 * Async to support multi-round protocols (FROST), hardware wallets, etc.
 */
export type Signer = {
  publicKey: [bigint, bigint];
  sign(message: bigint): Promise<{ R8: [bigint, bigint]; S: bigint }>;
};

/**
 * Extract an AccountView from a full Account.
 */
export function toAccountView(account: Account): AccountView {
  return {
    nullifyingKey: account.nullifyingKey,
    masterPublicKey: account.masterPublicKey,
    viewingKeyPair: account.viewingKeyPair,
    address: account.address,
  };
}

/**
 * Create a Signer from a single spending key pair.
 */
export function createSingleKeySigner(
  privateKey: Uint8Array,
  pubkey: [bigint, bigint],
): Signer {
  return {
    publicKey: pubkey,
    sign: async (message: bigint) => signTransactMessage(privateKey, message),
  };
}

export function deriveAccount(
  masterSeed: Uint8Array,
  accountIndex: number = 0,
): Account {
  const seed = normalizeMasterSeed(masterSeed);
  if (!Number.isInteger(accountIndex) || accountIndex < 0) {
    throw new ValidationError("accountIndex must be a non-negative integer");
  }

  const keys = deriveAccountKeys(seed, accountIndex);
  const address = encodeAddress({
    masterPublicKey: keys.masterPublicKey,
    viewingPublicKey: keys.viewing.pubkey,
  });

  return {
    spendingKeyPair: keys.spending,
    viewingKeyPair: keys.viewing,
    nullifyingKey: keys.nullifyingKey,
    masterPublicKey: keys.masterPublicKey,
    address,
  };
}

export function deriveAccountFromMnemonic(
  mnemonic: string,
  accountIndex: number = 0,
  password: string = "",
): Account {
  const normalized = normalizeMnemonic(mnemonic);
  const seed = mnemonicToSeed(normalized, password);
  try {
    return deriveAccount(seed, accountIndex);
  } finally {
    zeroize(seed);
  }
}

/** Passthrough crypto, storage handles buffer isolation */
const identityMasterSeedCrypto: MasterSeedCrypto = {
  encrypt: (seed) => seed,
  decrypt: (payload) => payload,
};

export async function generateMasterSeed({
  storage,
  rng,
  crypto = identityMasterSeedCrypto,
  overwrite = false,
  mnemonicPassphrase,
}: GenerateMasterSeedOptions): Promise<Uint8Array> {
  if (!overwrite) {
    const existingSeed = await loadMasterSeed(storage, crypto);
    if (existingSeed) return existingSeed;

    const existingMnemonic = await loadMasterMnemonic(storage, crypto);
    if (existingMnemonic) {
      const seedFromMnemonic = mnemonicToSeed(
        existingMnemonic,
        mnemonicPassphrase,
      );
      await storeMasterSeed(storage, seedFromMnemonic, crypto);
      return seedFromMnemonic;
    }
  }

  const entropy = rng(MNEMONIC_ENTROPY_BYTES);
  if (entropy.length !== MNEMONIC_ENTROPY_BYTES) {
    throw new ValidationError(
      `mnemonic entropy must be ${MNEMONIC_ENTROPY_BYTES} bytes`,
    );
  }

  try {
    const mnemonic = Mnemonic.fromEntropy(Hex.fromBytes(entropy));
    await storeMasterMnemonic(storage, mnemonic, crypto);
    const seed = mnemonicToSeed(mnemonic, mnemonicPassphrase);
    await storeMasterSeed(storage, seed, crypto);
    return seed;
  } finally {
    zeroize(entropy);
  }
}

export async function loadMasterSeed(
  storage: Storage,
  crypto: MasterSeedCrypto = identityMasterSeedCrypto,
): Promise<Uint8Array | null> {
  const stored = await storage.get(MASTER_SEED_KEY);
  if (!stored) return null;
  const plaintext = await crypto.decrypt(stored);
  return normalizeMasterSeed(plaintext);
}

export async function storeMasterSeed(
  storage: Storage,
  seed: Uint8Array,
  crypto: MasterSeedCrypto = identityMasterSeedCrypto,
): Promise<void> {
  const normalized = normalizeMasterSeed(seed);
  const encrypted = await crypto.encrypt(normalized);
  if (!(encrypted instanceof Uint8Array)) {
    throw new ValidationError("master seed encryptor must return Uint8Array");
  }
  await storage.put(MASTER_SEED_KEY, encrypted);
}

export async function loadMasterMnemonic(
  storage: Storage,
  crypto: MasterSeedCrypto = identityMasterSeedCrypto,
): Promise<string | null> {
  const stored = await storage.get(MASTER_MNEMONIC_KEY);
  if (!stored) return null;
  const plaintext = await crypto.decrypt(stored);
  try {
    const mnemonic = textDecoder.decode(plaintext);
    return normalizeMnemonic(mnemonic);
  } finally {
    zeroize(plaintext);
  }
}

export type ImportMasterMnemonicOptions = {
  storage: Storage;
  mnemonic: string;
  crypto?: MasterSeedCrypto;
  overwrite?: boolean;
  password?: string;
};

export async function importMasterMnemonic({
  storage,
  mnemonic,
  crypto = identityMasterSeedCrypto,
  overwrite = false,
  password = "",
}: ImportMasterMnemonicOptions): Promise<Uint8Array> {
  if (!overwrite) {
    const existing = await loadMasterMnemonic(storage, crypto);
    if (existing) {
      throw new ValidationError(
        "master mnemonic already exists; set overwrite to true to replace it",
      );
    }
  }

  const normalized = normalizeMnemonic(mnemonic);
  const seed = mnemonicToSeed(normalized, password);
  await storeMasterMnemonic(storage, normalized, crypto);
  await storeMasterSeed(storage, seed, crypto);
  return seed;
}

export async function storeMasterMnemonic(
  storage: Storage,
  mnemonic: string,
  crypto: MasterSeedCrypto = identityMasterSeedCrypto,
): Promise<void> {
  const normalized = normalizeMnemonic(mnemonic);
  const encrypted = await crypto.encrypt(textEncoder.encode(normalized));
  if (!(encrypted instanceof Uint8Array)) {
    throw new ValidationError(
      "master mnemonic encryptor must return Uint8Array",
    );
  }
  await storage.put(MASTER_MNEMONIC_KEY, encrypted);
}

/** Validates seed format. Storage handles buffer isolation on put/get. */
function normalizeMasterSeed(seed: Uint8Array): Uint8Array {
  if (!(seed instanceof Uint8Array)) {
    throw new ValidationError("master seed must be a Uint8Array");
  }
  if (seed.length !== MASTER_SEED_LENGTH) {
    throw new ValidationError(
      `master seed must be ${MASTER_SEED_LENGTH} bytes`,
    );
  }
  return seed;
}

function normalizeMnemonic(mnemonic: string): string {
  const formatted = mnemonic.trim().replace(/\s+/g, " ");
  if (!Mnemonic.validate(formatted)) {
    throw new ValidationError("invalid BIP-39 mnemonic phrase");
  }
  return formatted;
}

function mnemonicToSeed(mnemonic: string, password: string = ""): Uint8Array {
  const seedHex = Mnemonic.toSeed(mnemonic, password);
  return Hex.toBytes(seedHex);
}
