import { ValidationError } from "../errors.js";

export enum FieldSize {
  SCALAR = 32,
}

export type HexInput =
  | string
  | number
  | bigint
  | Uint8Array
  | ArrayLike<number>;

const HEX_REGEX = /^[0-9a-f]*$/i;

export class Hex {
  static strip(value: string): string {
    return value.startsWith("0x") ? value.slice(2) : value;
  }

  static encode(data: HexInput): string {
    if (typeof data === "string") return Hex.strip(data).toLowerCase();
    if (typeof data === "number" || typeof data === "bigint") {
      if (data < 0) throw new ValidationError("Cannot hexlify negative values");
      const hex = data.toString(16);
      return hex.length % 2 === 0 ? hex : `0${hex}`;
    }
    return Hex.fromBytes(
      data instanceof Uint8Array ? data : Uint8Array.from(data),
    );
  }

  static fromBytes(bytes: Uint8Array): string {
    return Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
  }

  static toBytes(hex: string): Uint8Array {
    const h = Hex.strip(hex).toLowerCase();
    if (h.length % 2 !== 0)
      throw new ValidationError("Hex string must have an even length");
    if (!HEX_REGEX.test(h)) throw new ValidationError("Invalid hex string");
    return Uint8Array.from({ length: h.length / 2 }, (_, i) =>
      parseInt(h.slice(i * 2, i * 2 + 2), 16),
    );
  }

  static toBigInt(hex: string): bigint {
    return BigInt(`0x${Hex.strip(hex)}`);
  }

  static padToSize(data: HexInput, size: FieldSize): string {
    const hex = Hex.encode(data);
    const target = size * 2;
    return hex.length > target
      ? hex.slice(0, target)
      : hex.padStart(target, "0");
  }

  static fromBigInt(value: bigint, size: FieldSize, prefix = false): string {
    const hex = value.toString(16).padStart(size * 2, "0");
    return prefix ? `0x${hex}` : hex;
  }
}
