import { ProofError } from "../errors.js";
import { ArtifactType } from "./config.js";

export class ArtifactIntegrityError extends ProofError {
  constructor(message: string) {
    super(message);
    this.name = "ArtifactIntegrityError";
  }
}

export function isArtifactIntegrityError(
  error: unknown,
): error is ArtifactIntegrityError {
  return error instanceof ArtifactIntegrityError;
}

interface ChecksumEntry {
  readonly sha256: string;
  readonly size: number;
}

export interface ChecksumsManifest {
  readonly version: string;
  readonly circuit: string;
  readonly generated: string;
  readonly files: Record<string, ChecksumEntry>;
}

function isObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parseChecksumEntry(value: unknown, fileName: string): ChecksumEntry {
  if (!isObject(value)) {
    throw new ArtifactIntegrityError(
      `checksums.json entry for ${fileName} must be an object`,
    );
  }

  const sha256 = value.sha256;
  if (typeof sha256 !== "string" || !/^[a-fA-F0-9]{64}$/.test(sha256)) {
    throw new ArtifactIntegrityError(
      `checksums.json entry for ${fileName} must include a valid sha256`,
    );
  }

  const size = value.size;
  if (typeof size !== "number" || !Number.isSafeInteger(size) || size < 0) {
    throw new ArtifactIntegrityError(
      `checksums.json entry for ${fileName} must include a valid size`,
    );
  }

  return {
    sha256: sha256.toLowerCase(),
    size,
  };
}

export function parseChecksumsManifest(
  rawManifest: unknown,
  expectedCircuitName: string,
  expectedVersion: string,
): ChecksumsManifest {
  if (!isObject(rawManifest)) {
    throw new ArtifactIntegrityError("checksums.json must be a JSON object");
  }

  const version = rawManifest.version;
  if (typeof version !== "string" || version.length === 0) {
    throw new ArtifactIntegrityError("checksums.json is missing version");
  }
  if (version !== expectedVersion) {
    throw new ArtifactIntegrityError(
      `checksums.json version mismatch: expected ${expectedVersion}, got ${version}`,
    );
  }

  const circuit = rawManifest.circuit;
  if (typeof circuit !== "string" || circuit.length === 0) {
    throw new ArtifactIntegrityError("checksums.json is missing circuit");
  }

  if (circuit !== expectedCircuitName) {
    throw new ArtifactIntegrityError(
      `checksums.json circuit mismatch: expected ${expectedCircuitName}, got ${circuit}`,
    );
  }

  const generated = rawManifest.generated;
  if (typeof generated !== "string" || generated.length === 0) {
    throw new ArtifactIntegrityError(
      "checksums.json is missing generated timestamp",
    );
  }

  const filesRaw = rawManifest.files;
  if (!isObject(filesRaw)) {
    throw new ArtifactIntegrityError("checksums.json is missing files map");
  }

  const files: Record<string, ChecksumEntry> = {};
  for (const [name, entry] of Object.entries(filesRaw)) {
    files[name] = parseChecksumEntry(entry, name);
  }

  return {
    version,
    circuit,
    generated,
    files,
  };
}

function toHex(bytes: Uint8Array): string {
  return Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0")).join(
    "",
  );
}

async function sha256Hex(data: Uint8Array): Promise<string> {
  const subtle = globalThis.crypto?.subtle;
  if (!subtle) {
    throw new ArtifactIntegrityError("SHA-256 is unavailable in this runtime");
  }

  // Force an ArrayBuffer-backed view to satisfy WebCrypto BufferSource typing.
  const digestInput = Uint8Array.from(data);
  const digest = await subtle.digest("SHA-256", digestInput);
  return toHex(new Uint8Array(digest));
}

export async function verifyArtifactIntegrity(
  manifest: ChecksumsManifest,
  circuitName: string,
  artifactType: ArtifactType,
  content: Uint8Array,
): Promise<void> {
  const entry = manifest.files[artifactType];
  if (!entry) {
    throw new ArtifactIntegrityError(
      `checksums.json for ${circuitName} is missing ${artifactType}`,
    );
  }

  if (content.byteLength !== entry.size) {
    throw new ArtifactIntegrityError(
      `artifact size mismatch for ${circuitName}/${artifactType}: expected ${entry.size}, got ${content.byteLength}`,
    );
  }

  const digest = await sha256Hex(content);
  if (digest !== entry.sha256) {
    throw new ArtifactIntegrityError(
      `artifact hash mismatch for ${circuitName}/${artifactType}: expected ${entry.sha256}, got ${digest}`,
    );
  }
}
