/**
 * Chain configuration for SDK initialization.
 */
import { InitializationError } from "./errors.js";
import { DEFAULT_ARTIFACT_BASE_URL } from "./prover/config.js";

/**
 * Supported chain identifiers.
 * Each maps to a full config (chainId, gateway, pool, artifacts).
 */
export type SupportedChain = "monad-testnet" | "monad-testnet-staging";

/**
 * Default public RPC URLs per chain (not fetched from remote config).
 */
export const DEFAULT_RPC_URLS: Record<SupportedChain, string> = {
  "monad-testnet": "https://testnet-rpc.monad.xyz",
  "monad-testnet-staging": "https://testnet-rpc.monad.xyz",
};

/**
 * Full configuration for a supported chain.
 */
export interface ChainConfig {
  chainId: number;
  gatewayUrl: string;
  frostUrl?: string;
  poolAddress: string;
  adapterAddress?: string;
  artifactVersion: string;
  artifactBaseUrl?: string;
  tokenAddresses?: Record<string, string>;
}

/**
 * Service configuration with broadcaster and indexer URLs.
 */
export interface ServiceConfig {
  broadcasterBaseUrl: string;
  indexerBaseUrl: string;
}

const CONFIG_URL = "https://config.unlink.xyz/networks.json";

function parseRequiredString(
  chain: string,
  field: string,
  value: unknown,
): string {
  if (typeof value !== "string" || value.trim().length === 0) {
    throw new InitializationError(
      `Invalid SDK config for ${chain}: ${field} must be a non-empty string`,
    );
  }
  return value.trim();
}

function parseOptionalString(
  chain: string,
  field: string,
  value: unknown,
): string | undefined {
  if (value === undefined) return undefined;
  if (typeof value !== "string" || value.trim().length === 0) {
    throw new InitializationError(
      `Invalid SDK config for ${chain}: ${field} must be a non-empty string when provided`,
    );
  }
  return value.trim();
}

function parseRequiredChainId(chain: string, value: unknown): number {
  if (typeof value !== "number" || !Number.isInteger(value) || value <= 0) {
    throw new InitializationError(
      `Invalid SDK config for ${chain}: chainId must be a positive integer`,
    );
  }
  return value;
}

function parseChainConfig(chain: string, value: unknown): ChainConfig {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    throw new InitializationError(
      `Invalid SDK config for ${chain}: expected object`,
    );
  }

  const raw = value as Record<string, unknown>;
  const chainId = parseRequiredChainId(chain, raw.chainId);
  const gatewayUrl = parseRequiredString(
    chain,
    "gatewayUrl",
    raw.gatewayUrl,
  ).replace(/\/+$/, "");
  const poolAddress = parseRequiredString(
    chain,
    "poolAddress",
    raw.poolAddress,
  );
  const artifactVersion = parseRequiredString(
    chain,
    "artifactVersion",
    raw.artifactVersion,
  ).replace(/^\/+|\/+$/g, "");
  const adapterAddress = parseOptionalString(
    chain,
    "adapterAddress",
    raw.adapterAddress,
  );
  const frostUrl = parseOptionalString(
    chain,
    "frostUrl",
    raw.frostUrl,
  )?.replace(/\/+$/, "");
  const artifactBaseUrl = parseOptionalString(
    chain,
    "artifactBaseUrl",
    raw.artifactBaseUrl,
  )?.replace(/\/+$/, "");

  let tokenAddresses: Record<string, string> | undefined;
  if (raw.tokenAddresses !== undefined) {
    if (
      raw.tokenAddresses === null ||
      typeof raw.tokenAddresses !== "object" ||
      Array.isArray(raw.tokenAddresses)
    ) {
      throw new InitializationError(
        `Invalid SDK config for ${chain}: tokenAddresses must be an object`,
      );
    }
    tokenAddresses = {};
    for (const [name, addr] of Object.entries(
      raw.tokenAddresses as Record<string, unknown>,
    )) {
      tokenAddresses[name] = parseRequiredString(
        chain,
        `tokenAddresses.${name}`,
        addr,
      );
    }
  }

  return {
    chainId,
    gatewayUrl,
    ...(frostUrl !== undefined ? { frostUrl } : {}),
    poolAddress,
    ...(adapterAddress !== undefined ? { adapterAddress } : {}),
    artifactVersion,
    ...(artifactBaseUrl !== undefined
      ? { artifactBaseUrl }
      : { artifactBaseUrl: DEFAULT_ARTIFACT_BASE_URL }),
    ...(tokenAddresses !== undefined ? { tokenAddresses } : {}),
  };
}

/**
 * Fetch chain configuration from the hosted network config file.
 *
 * @param chain - The chain to fetch config for
 * @returns Promise resolving to the chain configuration
 * @throws If fetch fails or chain is not found
 */
export async function fetchChainConfig(
  chain: SupportedChain,
): Promise<ChainConfig> {
  const res = await fetch(CONFIG_URL);
  if (!res.ok) {
    throw new InitializationError(`Failed to fetch SDK config: ${res.status}`);
  }
  const config = (await res.json()) as Record<string, unknown>;
  if (!config[chain]) {
    throw new InitializationError(
      `Unknown chain: "${chain}". Supported chains: ${Object.keys(config).join(", ")}`,
    );
  }
  return parseChainConfig(chain, config[chain]);
}

/**
 * Create service configuration from a gateway URL.
 *
 * @param gatewayUrl - The base gateway URL
 * @returns Service configuration with broadcaster and indexer URLs
 */
export function createServiceConfig(gatewayUrl: string): ServiceConfig {
  const baseUrl = gatewayUrl.replace(/\/+$/, "");
  return {
    broadcasterBaseUrl: baseUrl + "/broadcaster",
    indexerBaseUrl: baseUrl + "/indexer",
  };
}
