import type { FetchLike } from "./http.js";
import { createJsonHttpClient } from "./http.js";

export type BroadcasterRelayPayload = {
  kind: "call_data";
  to: string;
  data: string;
};

export type SubmitRelayParams = {
  clientTxId: string;
  chainId: number;
  payload: BroadcasterRelayPayload;
};

export type SubmitRelayResponse = {
  id: string;
  accepted: boolean;
  message?: string | null;
};

export type RelayState =
  | "pending"
  | "broadcasting"
  | "submitted"
  | "succeeded"
  | "reverted"
  | "failed"
  | "dead";

export type TransactionReceipt = {
  blockNumber?: number;
  blockHash?: string;
  transactionIndex?: number;
};

export type RelayStatusResponse = {
  id: string;
  state: RelayState;
  txHash?: string | null;
  receipt?: TransactionReceipt | null;
  error?: string | null;
};

// Internal type matching server's snake_case response
type RelayStatusRaw = {
  id: string;
  state: RelayState;
  tx_hash?: string | null;
  receipt?: TransactionReceipt | null;
  error?: string | null;
};

type BroadcasterClientDeps = {
  fetch: FetchLike;
};

const RELAY_STATUS_BATCH_LIMIT = 50;

function toRelayStatusResponse(raw: RelayStatusRaw): RelayStatusResponse {
  return {
    id: raw.id,
    state: raw.state,
    txHash: raw.tx_hash,
    receipt: raw.receipt,
    error: raw.error,
  };
}

function chunkArray<T>(items: T[], chunkSize: number): T[][] {
  const chunks: T[][] = [];
  for (let i = 0; i < items.length; i += chunkSize) {
    chunks.push(items.slice(i, i + chunkSize));
  }
  return chunks;
}

export function createBroadcasterClient(
  baseUrl: string,
  deps: BroadcasterClientDeps,
) {
  const http = createJsonHttpClient(baseUrl, deps);

  return {
    async submitRelay(params: SubmitRelayParams) {
      return http.request<SubmitRelayResponse>({
        method: "POST",
        path: "/relays",
        json: {
          client_tx_id: params.clientTxId,
          chain_id: params.chainId,
          ...params.payload,
        },
      });
    },

    async getRelayStatus(relayId: string): Promise<RelayStatusResponse> {
      const raw = await http.request<RelayStatusRaw>({
        method: "GET",
        path: `/relays/${relayId}`,
      });
      return toRelayStatusResponse(raw);
    },

    async getRelayStatusBatch(
      relayIds: string[],
    ): Promise<RelayStatusResponse[]> {
      if (relayIds.length === 0) return [];

      const chunks = chunkArray(relayIds, RELAY_STATUS_BATCH_LIMIT);

      const results = await Promise.all(
        chunks.map(async (chunk) => {
          const raw = await http.request<{ relays: RelayStatusRaw[] }>({
            method: "GET",
            path: `/relays/batch?ids=${chunk.join(",")}`,
          });
          return raw.relays.map(toRelayStatusResponse);
        }),
      );
      return results.flat();
    },
  };
}
