import { CoreError } from "../errors.js";

/**
 * Generate a cryptographically secure random bigint.
 * @param bytes - Number of bytes of randomness (default: 32 for 256-bit)
 * @returns Random bigint
 */
export function randomBigint(bytes = 32): bigint {
  if (typeof globalThis.crypto?.getRandomValues !== "function") {
    throw new CoreError("crypto.getRandomValues is not available");
  }
  const buffer = new Uint8Array(bytes);
  globalThis.crypto.getRandomValues(buffer);
  return BigInt(
    "0x" +
      Array.from(buffer)
        .map((b) => b.toString(16).padStart(2, "0"))
        .join(""),
  );
}

/**
 * Generate a cryptographically secure random hex string.
 * @param bytes - Number of bytes of randomness
 * @returns Random hex string with 0x prefix
 */
export function randomHex(bytes: number): `0x${string}` {
  return `0x${randomBigint(bytes)
    .toString(16)
    .padStart(bytes * 2, "0")}` as `0x${string}`;
}

/**
 * Generate a unique relay ID for transaction tracking.
 * Uses crypto.randomUUID() when available, falls back to 128-bit random hex.
 */
export function generateRelayId(prefix: string): string {
  return (
    globalThis.crypto?.randomUUID?.() ?? `${prefix}-${randomHex(16).slice(2)}`
  );
}
