import { InitializationError } from "./errors.js";
import { migrate } from "./schema.js";
import type { Storage } from "./types.js";

export type CoreDeps = {
  storage: Storage;
  rng: (n: number) => Uint8Array;
};

export async function initCore(deps: CoreDeps) {
  if (!deps?.storage) throw new InitializationError("storage dep required");
  if (!deps?.rng) throw new InitializationError("rng dep required");

  await migrate(deps.storage);
  return {
    storage: deps.storage,
    rng: deps.rng,
  };
}
