export const ACCOUNT_RECORD_VERSION = 1;
export const BIGINT_RADIX = 16;

export type CoreSDK = Awaited<ReturnType<typeof initCore>>;

export type WalletDeps = {
  core: CoreSDK;
  fetch: typeof globalThis.fetch;
};

/**
 * Account info without private keys, safe for display.
 */
export type AccountInfo = {
  index: number;
  masterPublicKey: bigint;
  /** Bech32m address (unlink1...) */
  address: string;
};

/**
 * Seed management API for mnemonic/master seed operations.
 * Derived from SeedService, excluding internal getMasterSeed method.
 */
export type SeedAPI = Omit<SeedService, "getMasterSeed">;

/**
 * Account management API for multi-account support.
 */
export type WalletAccountAPI = {
  /**
   * List all derived accounts (index + mpk only).
   */
  list(): Promise<AccountInfo[]>;

  /**
   * Get full Account by index.
   */
  get(index: number): Promise<Account | null>;

  /**
   * Derive and persist a new account.
   * @param index Optional specific index, otherwise uses next available
   */
  create(index?: number): Promise<Account>;

  /**
   * Get the currently active account.
   */
  getActive(): Promise<Account | null>;

  /**
   * Get the currently active account index.
   */
  getActiveIndex(): Promise<number | null>;

  /**
   * Switch to a different account.
   * @throws If account at index doesn't exist
   */
  setActive(index: number): Promise<void>;
};

// Deposit types
// Named differently from core's DepositParams to avoid collision
export type WalletDepositParams = {
  chainId: number;
  poolAddress: string;
  depositor: string;
  deposits: Array<{
    token: string;
    amount: bigint;
  }>;
  /** Override account for multisig deposits (defaults to active account). */
  account?: AccountView;
};

export type WalletDepositResult = DepositRelayResult;

export type WalletDepositAPI = {
  /**
   * Request a deposit (1 or more tokens).
   */
  request(params: WalletDepositParams): Promise<WalletDepositResult>;
  /**
   * Wait for deposit to be confirmed on-chain.
   */
  reconcile(relayId: string): Promise<DepositSyncResult>;
};

export type WalletNoteInsert = {
  chainId: number;
  index: number;
  token: string;
  amount: bigint;
  commitment: string;
  npk: bigint;
  mpk: bigint;
  random: bigint;
  nullifier: bigint;
};

export type WalletNoteAPI = {
  import(note: WalletNoteInsert): Promise<void>;
  list(
    chainId: number,
    overrides?: { account: AccountView },
  ): Promise<NoteRecord[]>;
};

export type WalletSyncAPI = {
  syncChain(
    chainId: number,
    account: AccountView,
    opts?: { forceFullResync?: boolean },
  ): Promise<void>;
  syncChains(
    chainIds: number[],
    account: AccountView,
    opts?: { forceFullResync?: boolean },
  ): Promise<void>;
  startAutoSync(intervalMs?: number): Promise<void>;
  stopAutoSync(): void;
};

export type WalletTxAPI = {
  /**
   * Get the status of a transaction from the broadcaster.
   * @param txId - The transaction ID returned from deposit, transfer, or withdraw operations
   */
  getStatus(txId: string): Promise<RelayStatusResponse>;
  /**
   * Start tracking a transaction for status updates.
   * Emits 'tx-status-changed' events when the transaction state changes.
   * Tracking automatically stops when the transaction reaches a terminal state.
   * @param txId - The transaction ID to track
   */
  track(txId: string): void;
  /**
   * Stop tracking a transaction.
   * @param txId - The transaction ID to stop tracking
   */
  untrack(txId: string): void;
};

export type SignerOverride = {
  signer: Signer;
  account: AccountView;
};

export type WalletTransactAPI = {
  transact(
    params: {
      chainId: number;
      poolAddress: string;
      transactions: Array<{
        token: string;
        inputs: Array<{ index: number }>;
        outputs: NoteInput[];
        withdrawal?: WithdrawalNoteInput;
        adapterDataHash?: bigint;
      }>;
    },
    opts?: { skipBroadcast?: boolean },
    overrides?: SignerOverride,
  ): Promise<TransactRelayResult>;
  reconcile(relayId: string): Promise<TransactSyncResult>;
};

export type SpendInput = {
  token: string;
  amount: bigint;
};

/** @deprecated Use {@link SpendInput} instead. */
export type InputTokenSpec = SpendInput;

export type ReceiveInput = {
  token: string;
  minAmount: bigint;
};

/** @deprecated Use {@link ReceiveInput} instead. */
export type ReshieldInput = ReceiveInput;

export type WalletInteractParams = {
  chainId: number;
  poolAddress: string;
  adapterAddress: string;
  spend: SpendInput[];
  calls: AdapterExecutionCall[];
  receive: ReceiveInput[];
  deadline?: bigint;
};

export type InteractResult = {
  relayId: string;
  adapterCalldata: string;
  transactCalldata: string;
  transactResult: TransactRelayResult;
  reshields: AdapterExecutionReshield[];
};

export type WalletInteractAPI = {
  execute(
    params: WalletInteractParams,
    opts?: { skipBroadcast?: boolean },
    overrides?: SignerOverride,
  ): Promise<InteractResult>;
};

export type WalletHistoryAPI = {
  list(
    chainId: number,
    options?: { includeSelfSends?: boolean },
    overrides?: { account: AccountView },
  ): Promise<HistoryEntry[]>;
};

// High-level send types
export type SendParams = {
  chainId: number;
  poolAddress: string;
  transfers: Array<{
    token: string;
    recipient: string; // Unlink address (unlink1... bech32m)
    amount: bigint;
  }>;
};

export type SendPlanResult<T = NoteRecord> = TransactionPlan<T>[];

export type SendResult = {
  relayId: string;
  plans: SendPlanResult;
  transactResult: TransactRelayResult;
};

// High-level withdraw types
export type WithdrawParams = {
  chainId: number;
  poolAddress: string;
  withdrawals: Array<{
    token: string;
    amount: bigint;
    recipient: string; // EOA address
  }>;
};

export type WithdrawPlanResult<T = NoteRecord> = WithdrawalPlan<T>[];

export type WithdrawResult = {
  relayId: string;
  plans: WithdrawPlanResult;
  transactResult: TransactRelayResult;
};

export type WalletBalanceAPI = {
  /**
   * Get balances for all tokens on a chain.
   */
  list(
    chainId: number,
    overrides?: { account: AccountView },
  ): Promise<Record<string, bigint>>;
  /**
   * Get balance for a specific token on a chain.
   */
  get(
    chainId: number,
    token: string,
    overrides?: { account: AccountView },
  ): Promise<bigint>;
};

export type WalletSendAPI = {
  /**
   * High-level send: 1 or more transfers.
   * SDK handles note selection, circuit selection, and proof generation.
   * Generates proofs in parallel and submits as one atomic operation.
   */
  send(params: SendParams, overrides?: SignerOverride): Promise<SendResult>;
  /**
   * Get a send plan without executing.
   * Useful for showing the user what will happen before confirming.
   */
  plan(params: SendParams, account?: AccountView): Promise<SendPlanResult>;
  /**
   * Execute a pre-built send plan.
   */
  execute(
    plans: SendPlanResult,
    params: Pick<SendParams, "chainId" | "poolAddress">,
    overrides?: SignerOverride,
  ): Promise<SendResult>;
};

export type WalletWithdrawAPI = {
  /**
   * High-level withdraw: 1 or more withdrawals.
   * SDK handles note selection, circuit selection, and proof generation.
   * Generates proofs in parallel and submits as one atomic operation.
   */
  send(
    params: WithdrawParams,
    overrides?: SignerOverride,
  ): Promise<WithdrawResult>;
  /**
   * Get a withdrawal plan without executing.
   * Useful for showing the user what will happen before confirming.
   */
  plan(
    params: WithdrawParams,
    account?: AccountView,
  ): Promise<WithdrawPlanResult>;
  /**
   * Execute a pre-built withdrawal plan.
   */
  execute(
    plans: WithdrawPlanResult,
    params: Pick<WithdrawParams, "chainId" | "poolAddress">,
    overrides?: SignerOverride,
  ): Promise<WithdrawResult>;
};

export type TxStatusChangedEvent = {
  type: "tx-status-changed";
  txId: string;
  state: RelayState;
  previousState: RelayState | null;
  txHash?: string;
  blockNumber?: number;
  error?: string;
};

export type UnlinkEvent =
  | { type: "notes-updated"; chainId: number }
  | { type: "sync-error"; error: string }
  | { type: "wallet-created" }
  | { type: "account-created"; index: number }
  | { type: "account-switched"; index: number }
  | TxStatusChangedEvent;

/** @deprecated Use {@link UnlinkEvent} instead. */
export type WalletSDKEvent = UnlinkEvent;

export type WalletSDK = {
  seed: SeedAPI;
  accounts: WalletAccountAPI;
  balances: WalletBalanceAPI;
  /** Burner accounts — BIP-44 derived EOAs for DeFi interactions */
  burner: BurnerAPI;
  /** Private DeFi adapter interaction flow */
  adapter: WalletInteractAPI;
  deposit: WalletDepositAPI;
  history: WalletHistoryAPI;
  notes: WalletNoteAPI;
  transact: WalletTransactAPI;
  transfer: WalletSendAPI;
  withdraw: WalletWithdrawAPI;
  events: {
    on(fn: (event: UnlinkEvent) => void): () => void;
  };
  sync: WalletSyncAPI;
  tx: WalletTxAPI;
};

