// ===== Unlink types (simplified, no chainId/poolAddress per-call) =====

/**
 * Configuration for Unlink.create().
 * Either provide a chain name to auto-resolve, or explicit gatewayUrl + poolAddress.
 */
export type UnlinkCreateConfig =
  | {
      /** Supported chain name — resolves chainId, gateway, pool, artifacts automatically */
      chain: SupportedChain;
      /** Override pool address from chain config */
      poolAddress?: string;
      /** Override adapter address from chain config */
      adapterAddress?: string;
      /** Direct chain RPC for burner EOA transactions. Defaults to gatewayUrl. */
      chainRpcUrl?: string;
      /** Storage backend (auto-detected in browser, required in Node) */
      storage?: Storage;
      /** Random number generator (auto-detected via crypto.getRandomValues) */
      rng?: (n: number) => Uint8Array;
      /** Fetch implementation (defaults to globalThis.fetch) */
      fetch?: typeof globalThis.fetch;
      /** Prover/artifact source configuration */
      prover?: ProverConfig;
      /** Disable auto-sync scheduler (default: true). Set false for CLI/script usage. */
      autoSync?: boolean;
    }
  | {
      /** Chain ID for the target blockchain */
      chainId: number;
      /** Explicit gateway URL */
      gatewayUrl: string;
      /** Pool contract address */
      poolAddress: string;
      /** Adapter contract address */
      adapterAddress?: string;
      /** Direct chain RPC for burner EOA transactions. Defaults to gatewayUrl. */
      chainRpcUrl?: string;
      /** Storage backend (auto-detected in browser, required in Node) */
      storage?: Storage;
      /** Random number generator (auto-detected via crypto.getRandomValues) */
      rng?: (n: number) => Uint8Array;
      /** Fetch implementation (defaults to globalThis.fetch) */
      fetch?: typeof globalThis.fetch;
      /** Prover/artifact source configuration */
      prover?: ProverConfig;
      /** Disable auto-sync scheduler (default: true). Set false for CLI/script usage. */
      autoSync?: boolean;
    };

/** @deprecated Use {@link UnlinkCreateConfig} instead. */
export type UnlinkWalletConfig = UnlinkCreateConfig;

/**
 * Prover configuration for artifact source.
 * Matches ServiceOptions["prover"] shape.
 */
export type ProverConfig = {
  artifactSource?: {
    baseUrl?: string;
    version?: string;
    preferLocalFiles?: boolean;
  };
};

