import type { HistoryEntry } from "../../history/types.js";
import { keys } from "../../keys.js";
import type { Storage } from "../../types.js";
import {
  decodeJson,
  encodeJson,
  type JsonRecord,
} from "../../utils/json-codec.js";
import { ensureChainId, ensureMpk } from "../../utils/validators.js";

type HistoryEntryRecord = HistoryEntry;
type HistoryMetaRecord = { v: 1; updatedAtMs: number };

export function createHistoryStore(storage: Storage) {
  async function putMeta(options: { chainId: number; mpk: string }) {
    await storage.put(
      keys.historyMeta(options.chainId, options.mpk),
      encodeJson({ v: 1, updatedAtMs: Date.now() } satisfies HistoryMetaRecord),
    );
  }

  return {
    async putHistoryEntry(entry: HistoryEntryRecord) {
      ensureChainId(entry.chainId);
      ensureMpk(entry.mpk);
      const key = keys.historyEntry(entry.id);
      await storage.put(key, encodeJson(entry as JsonRecord));
    },

    async hasHistorySnapshot(options: { chainId: number; mpk: string }) {
      ensureChainId(options.chainId);
      ensureMpk(options.mpk);
      const meta = await storage.get(
        keys.historyMeta(options.chainId, options.mpk),
      );
      return meta !== null;
    },

    async listHistoryEntries(options: { chainId: number; mpk: string }) {
      ensureChainId(options.chainId);
      ensureMpk(options.mpk);
      const prefix = keys.historyPrefix(options.chainId, options.mpk);
      const entries = await storage.iter({ prefix });
      const decoded = entries
        .filter(({ key }) => !key.endsWith(":__meta__"))
        .map(({ value }) => decodeJson<HistoryEntry>(value));
      decoded.sort((a, b) => {
        const at = a.timestamp ?? 0;
        const bt = b.timestamp ?? 0;
        if (at !== bt) return bt - at;
        return b.txHash.localeCompare(a.txHash);
      });
      return decoded;
    },

    async clearHistoryEntries(options: { chainId: number; mpk: string }) {
      ensureChainId(options.chainId);
      ensureMpk(options.mpk);
      const prefix = keys.historyPrefix(options.chainId, options.mpk);
      const existing = await storage.iter({ prefix });
      if (existing.length === 0) return;
      await storage.batch(existing.map(({ key }) => ({ del: key })));
    },

    async commitHistorySnapshot(options: { chainId: number; mpk: string }) {
      ensureChainId(options.chainId);
      ensureMpk(options.mpk);
      await putMeta(options);
    },
  };
}
