import { CoreError } from "../../errors.js";
import { parseHexToBigInt } from "../../utils/bigint.js";

export type BatchLeafLoader = (
  chainId: number,
) => Promise<{ commitment: string; index: number }[]>;

type TreesInterface = {
  reset(chainId: number): void;
  addLeaf(chainId: number, value: bigint): { index: number };
  getLeafCount?(chainId: number): number;
};

export async function rebuildTreeFromStore({
  chainId,
  trees,
  loadLeaves,
}: {
  chainId: number;
  trees: TreesInterface;
  loadLeaves: BatchLeafLoader;
}) {
  trees.reset(chainId);

  const leaves = await loadLeaves(chainId);
  for (const leaf of leaves) {
    const { index } = trees.addLeaf(chainId, parseHexToBigInt(leaf.commitment));
    if (index !== leaf.index) {
      throw new CoreError(
        `stored leaves are inconsistent with local tree, expected ${leaf.index}, got ${index}`,
      );
    }
  }
  return leaves.length;
}

export type HydrateChainParams = {
  chainId: number;
  trees: TreesInterface;
  loadLeaves: BatchLeafLoader;
  hydrated: Set<number>;
};

/**
 * Hydrate the in-memory merkle tree for a chain, skipping if already done.
 * Call `hydrated.delete(chainId)` to invalidate and force a rebuild.
 */
export async function hydrateChain({
  chainId,
  trees,
  loadLeaves,
  hydrated,
}: HydrateChainParams): Promise<number> {
  if (hydrated.has(chainId)) {
    return trees.getLeafCount?.(chainId) ?? 0;
  }
  const count = await rebuildTreeFromStore({
    chainId,
    trees,
    loadLeaves,
  });
  hydrated.add(chainId);
  return count;
}
