const DEFAULT_SYNC_INTERVAL_MS = 5_000;

function resolveWalletProverConfig(
  prover?: ServiceOptions["prover"],
): ServiceOptions["prover"] {
  if (prover !== undefined) {
    return prover;
  }

  if (typeof process !== "undefined" && process.versions?.node) {
    const envVersion = (process.env.UNLINK_ARTIFACT_VERSION ?? "")
      .trim()
      .replace(/^\/+|\/+$/g, "");
    const envBaseUrl = (process.env.UNLINK_ARTIFACT_BASE_URL ?? "")
      .trim()
      .replace(/\/+$/, "");

    // Node defaults to local-first only when no pinned env version is configured.
    // If a pinned version is present, prefer remote-first to avoid silently using stale local artifacts.
    return {
      artifactSource: {
        ...(envVersion.length === 0 ? { preferLocalFiles: true } : {}),
        ...(envBaseUrl.length > 0 ? { baseUrl: envBaseUrl } : {}),
        ...(envVersion.length > 0 ? { version: envVersion } : {}),
      },
    };
  }

  return undefined;
}

function createEventBus() {
  const listeners = new Set<(event: WalletSDKEvent) => void>();
  return {
    on(fn: (event: WalletSDKEvent) => void) {
      listeners.add(fn);
      return () => listeners.delete(fn);
    },
    emit(event: WalletSDKEvent) {
      listeners.forEach((fn) => {
        try {
          fn(event);
        } catch (err) {
          console.error("[sdk] event handler failed", err);
        }
      });
    },
  };
}

function createSyncScheduler(
  run: () => Promise<void>,
  onError?: (err: unknown) => void,
) {
  let timer: ReturnType<typeof setInterval> | null = null;
  let running = false;

  const tick = async () => {
    if (running) return;
    running = true;
    try {
      await run();
    } catch (err) {
      console.error("[sdk] auto-sync failed", err);
      onError?.(err);
    } finally {
      running = false;
    }
  };

  return {
    start(intervalMs = DEFAULT_SYNC_INTERVAL_MS) {
      if (timer) return;
      timer = setInterval(tick, intervalMs);
      void tick();
    },
    stop() {
      if (timer) {
        clearInterval(timer);
        timer = null;
      }
    },
  };
}

const TERMINAL_TX_STATES: readonly RelayState[] = [
  "succeeded",
  "reverted",
  "failed",
  "dead",
];

const TX_POLL_INTERVAL_MS = 2_000;

type TrackedTx = {
  state: RelayState | null;
  txHash?: string;
  blockNumber?: number;
  error?: string;
};

function createTxTracker(
  broadcasterClient: ReturnType<typeof createBroadcasterClient>,
  emit: (event: TxStatusChangedEvent) => void,
) {
  const tracked = new Map<string, TrackedTx>();
  let timer: ReturnType<typeof setInterval> | null = null;
  let polling = false;

  const pollTracked = async () => {
    if (polling || tracked.size === 0) return;
    polling = true;

    try {
      const txIds = [...tracked.keys()];
      const responses = await broadcasterClient.getRelayStatusBatch(txIds);
      const responseMap = new Map(responses.map((r) => [r.id, r]));

      for (const txId of txIds) {
        const prev = tracked.get(txId);
        if (!prev) continue;

        const response = responseMap.get(txId);
        if (!response) continue;

        const newState = response.state;
        if (prev.state !== newState) {
          emit({
            type: "tx-status-changed",
            txId,
            state: newState,
            previousState: prev.state,
            txHash: response.txHash ?? undefined,
            blockNumber: response.receipt?.blockNumber,
            error: response.error ?? undefined,
          });

          tracked.set(txId, {
            state: newState,
            txHash: response.txHash ?? undefined,
            blockNumber: response.receipt?.blockNumber,
            error: response.error ?? undefined,
          });

          if (TERMINAL_TX_STATES.includes(newState)) {
            tracked.delete(txId);
          }
        }
      }
    } catch (err) {
      console.error("[sdk] failed to poll tx status batch:", err);
    } finally {
      polling = false;
    }

    // Stop timer if nothing left to track
    if (tracked.size === 0 && timer) {
      clearInterval(timer);
      timer = null;
    }
  };

  const ensureTimer = () => {
    if (!timer && tracked.size > 0) {
      timer = setInterval(pollTracked, TX_POLL_INTERVAL_MS);
      // Immediate first poll
      void pollTracked();
    }
  };

  return {
    track(txId: string) {
      if (!txId?.trim()) return;
      if (!tracked.has(txId)) {
        tracked.set(txId, { state: null });
        ensureTimer();
      }
    },
    untrack(txId: string) {
      tracked.delete(txId);
      if (tracked.size === 0 && timer) {
        clearInterval(timer);
        timer = null;
      }
    },
    stop() {
      if (timer) {
        clearInterval(timer);
        timer = null;
      }
      tracked.clear();
    },
  };
}

/**
 * @internal Use {@link Unlink.create} instead.
 */
export function createWalletSDK(
  deps: WalletDeps,
  options: {
    chainId?: number;
    /** Gateway URL for relayed transactions (indexer, broadcaster) */
    gatewayUrl: string;
    /** Direct chain RPC for burner EOA transactions. Defaults to gatewayUrl. */
    chainRpcUrl?: string;
    prover?: ServiceOptions["prover"];
    /** Disable auto-sync scheduler (default: true). Set false for CLI/script usage. */
    autoSync?: boolean;
  },
): WalletSDK {
  if (!deps || deps.core === undefined || deps.core === null) {
    throw new InitializationError("core dependency is required");
  }
  if (!deps.fetch) {
    throw new InitializationError("fetch dependency is required");
  }
  if (!options?.gatewayUrl) {
    throw new InitializationError("gatewayUrl is required");
  }

  const fetchImpl = deps.fetch;
  const { storage, rng } = deps.core;
  const stateStore = createStateStore(storage);
  const merkleTrees = createMerkleTrees();
  const serviceConfig = createServiceConfig(options.gatewayUrl);

  // Shared options for transaction operations
  const txOpts: ServiceOptions = {
    fetch: fetchImpl,
    merkleTrees,
    gatewayUrl: options.gatewayUrl,
    prover: resolveWalletProverConfig(options.prover),
  };

  const indexerClient = createIndexerClient(serviceConfig.indexerBaseUrl, {
    fetch: fetchImpl,
  });
  const broadcasterClient = createBroadcasterClient(
    serviceConfig.broadcasterBaseUrl,
    { fetch: fetchImpl },
  );
  const syncService = createNoteSyncService(stateStore, {
    merkleTrees,
    indexerClient,
    fetch: fetchImpl,
  });
  const historyService = createHistoryService(stateStore);
  const events = createEventBus();
  const txTracker = createTxTracker(broadcasterClient, events.emit);
  const reconciler = createJobReconciler({
    stateStore,
    depositClient: {
      syncPendingDeposit: (relayId: string) =>
        syncDeposit(stateStore, relayId, txOpts),
    },
    transactService: {
      syncPendingTransact: (relayId: string) =>
        syncTransact(stateStore, relayId, txOpts),
    },
  });
  const seedService: SeedService = createSeedService({
    storage,
    rng,
  });
  const accountsService: AccountsService = createAccountsService({
    storage,
    deriveAccount,
    getMasterSeed: () => seedService.getMasterSeed(),
  });
  const chainRpcUrl = options.chainRpcUrl ?? options.gatewayUrl;

  const configuredChainId = options?.chainId ?? null;
  const scheduler = createSyncScheduler(
    async () => {
      if (!configuredChainId) {
        console.warn("[sdk] no chain id configured; skipping auto-sync");
        return;
      }

      // Check if wallet and account exist before syncing
      const walletExists = await seedService.exists();
      if (!walletExists) {
        // No wallet yet, skip sync
        return;
      }

      const account = await accountsService.getActive();
      if (!account) {
        // No active account, skip sync
        return;
      }

      const mpk = formatUint256(account.masterPublicKey);
      console.log("[sdk] auto-syncing chain", configuredChainId);
      await syncService.syncChains([configuredChainId], account);
      await reconciler.reconcileAll();
      await historyService.rebuildHistory({ chainId: configuredChainId, mpk });
      events.emit({ type: "notes-updated", chainId: configuredChainId });
    },
    (err) => {
      events.emit({
        type: "sync-error",
        error: err instanceof Error ? err.message : String(err),
      });
    },
  );

  // Helper to get active account or throw
  async function requireActiveAccount(): Promise<Account> {
    const account = await accountsService.getActive();
    if (!account) {
      throw new Error("No active account. Create an account first.");
    }
    return account;
  }

  function requireSigner(
    acct: AccountView,
  ): ReturnType<typeof createSingleKeySigner> {
    if (!("spendingKeyPair" in acct)) {
      throw new Error(
        "No signer: account has no spending key and no SignerOverride was provided",
      );
    }
    const { spendingKeyPair } = acct as Account;
    return createSingleKeySigner(
      spendingKeyPair.privateKey,
      spendingKeyPair.pubkey,
    );
  }

  const adapterService = createAdapterService({
    stateStore,
    txOpts,
    broadcasterClient,
    requireActiveAccount,
    requireSigner,
  });

  // Only auto-start scheduler if chain ID is configured and autoSync is not disabled.
  // CLI/scripts set autoSync=false to prevent the scheduler from racing with manual sync.
  if (configuredChainId && options.autoSync !== false) {
    scheduler.start();
  }

  // --- Burner plugin (self-contained, easy to remove) ---
  let burnerService: BurnerService | undefined;
  function getBurnerService(): BurnerService {
    if (!burnerService) {
      burnerService = createBurnerService({
        chainRpcUrl,
        getMasterSeed: () => seedService.getMasterSeed(),
        withdrawToAddress: (p) => sdk.withdraw.send(p),
        requestDeposit: (p) => sdk.deposit.request(p),
      });
    }
    return burnerService;
  }

  const sdk: WalletSDK = {
    seed: {
      async exists(): Promise<boolean> {
        return seedService.exists();
      },
      async create(): Promise<{ mnemonic: string }> {
        const result = await seedService.create();
        events.emit({ type: "wallet-created" });
        return result;
      },
      async importMnemonic(
        mnemonic: string,
        opts?: { overwrite?: boolean },
      ): Promise<void> {
        await seedService.importMnemonic(mnemonic, opts);
        if (opts?.overwrite) {
          burnerService = undefined;
        }
        events.emit({ type: "wallet-created" });
      },
      async exportMnemonic(): Promise<string> {
        return seedService.exportMnemonic();
      },
      async delete(): Promise<void> {
        scheduler.stop();
        txTracker.stop();
        burnerService = undefined;
        await seedService.delete();
      },
    },
    accounts: {
      async list(): Promise<AccountInfo[]> {
        return accountsService.list();
      },
      async get(index: number): Promise<Account | null> {
        return accountsService.get(index);
      },
      async create(index?: number): Promise<Account> {
        const account = await accountsService.create(index);
        const accounts = await accountsService.list();
        const createdAccount = accounts.find(
          (a) => a.masterPublicKey === account.masterPublicKey,
        );
        if (!createdAccount) {
          throw new Error("Failed to find newly created account");
        }
        events.emit({
          type: "account-created",
          index: createdAccount.index,
        });
        return account;
      },
      async getActive(): Promise<Account | null> {
        return accountsService.getActive();
      },
      async getActiveIndex(): Promise<number | null> {
        return accountsService.getActiveIndex();
      },
      async setActive(index: number): Promise<void> {
        await accountsService.setActive(index);
        events.emit({ type: "account-switched", index });
      },
    },
    burner: {
      async addressOf(index: number): Promise<BurnerAccount> {
        return getBurnerService().addressOf(index);
      },
      async send(
        index: number,
        tx: BurnerSendParams,
      ): Promise<{ txHash: string }> {
        return getBurnerService().send(index, tx);
      },
      async exportKey(index: number): Promise<string> {
        return getBurnerService().exportKey(index);
      },
      async fund(
        index: number,
        params: BurnerFundParams,
      ): Promise<WithdrawResult> {
        await requireActiveAccount();
        return getBurnerService().fund(index, params);
      },
      async getTokenBalance(address: string, token: string): Promise<bigint> {
        return getBurnerService().getTokenBalance(address, token);
      },
      async getBalance(address: string): Promise<bigint> {
        return getBurnerService().getBalance(address);
      },
      async sweepToPool(
        index: number,
        params: BurnerSweepToPoolParams,
      ): Promise<{ txHash: string }> {
        await requireActiveAccount();
        return getBurnerService().sweepToPool(index, params);
      },
    },
    adapter: {
      execute: async (params, opts, overrides) =>
        adapterService.execute(params, opts, overrides),
    },
    balances: {
      async list(
        chainId: number,
        overrides?: { account: AccountView },
      ): Promise<Record<string, bigint>> {
        ensureChainId(chainId);
        const account = overrides?.account ?? (await requireActiveAccount());
        const notes = await stateStore.listNotes({
          chainId,
          mpk: formatUint256(account.masterPublicKey),
          includeSpent: false,
        });
        return computeBalances(notes);
      },
      async get(
        chainId: number,
        token: string,
        overrides?: { account: AccountView },
      ): Promise<bigint> {
        const balances = await this.list(chainId, overrides);
        return balances[token.toLowerCase()] ?? 0n;
      },
    },
    deposit: {
      async request(params: WalletDepositParams): Promise<WalletDepositResult> {
        ensureChainId(params.chainId);
        const account = params.account ?? (await requireActiveAccount());

        // Generate randoms for each note using configured rng
        const notes = params.deposits.map((d) => {
          const randomBytes = rng(32);
          const random = BigInt(
            "0x" +
              [...randomBytes]
                .map((b) => b.toString(16).padStart(2, "0"))
                .join(""),
          );
          return {
            mpk: account.masterPublicKey,
            random,
            token: d.token,
            amount: d.amount,
            viewingPublicKey: account.viewingKeyPair.pubkey,
          };
        });

        return deposit(stateStore, {
          account,
          chainId: params.chainId,
          poolAddress: params.poolAddress,
          depositor: params.depositor,
          notes,
        });
      },
      async reconcile(relayId: string): Promise<DepositSyncResult> {
        const result = (await reconciler.reconcileRelay(
          relayId,
        )) as DepositSyncResult;
        const account = await requireActiveAccount();
        await historyService.rebuildHistory({
          chainId: result.chainId,
          mpk: formatUint256(account.masterPublicKey),
        });
        return result;
      },
    },
    history: {
      async list(
        chainId: number,
        options?: { includeSelfSends?: boolean },
        overrides?: { account: AccountView },
      ) {
        ensureChainId(chainId);
        const account = overrides?.account ?? (await requireActiveAccount());
        return historyService.getHistory({
          chainId,
          mpk: formatUint256(account.masterPublicKey),
          includeSelfSends: options?.includeSelfSends,
        });
      },
    },
    notes: {
      async import(note: WalletNoteInsert) {
        ensureChainId(note.chainId);
        const mpk = formatUint256(note.mpk);
        await stateStore.putNote({
          chainId: note.chainId,
          index: note.index,
          token: note.token,
          value: note.amount.toString(),
          commitment: note.commitment,
          npk: formatUint256(note.npk),
          mpk: formatUint256(note.mpk),
          random: formatUint256(note.random),
          nullifier: formatUint256(note.nullifier),
        });
        await historyService.rebuildHistory({ chainId: note.chainId, mpk });
      },
      async list(
        chainId: number,
        overrides?: { account: AccountView },
      ): Promise<NoteRecord[]> {
        ensureChainId(chainId);
        const account = overrides?.account ?? (await requireActiveAccount());
        return stateStore.listNotes({
          chainId,
          mpk: formatUint256(account.masterPublicKey),
          includeSpent: true,
        });
      },
    },
    transact: {
      async transact(
        params: {
          chainId: number;
          poolAddress: string;
          transactions: Array<{
            token: string;
            inputs: Array<{ index: number }>;
            outputs: NoteInput[];
            withdrawal?: WithdrawalNoteInput;
            adapterDataHash?: bigint;
          }>;
        },
        opts?: { skipBroadcast?: boolean },
        overrides?: SignerOverride,
      ) {
        const acct = overrides?.account ?? (await requireActiveAccount());
        const signer = overrides?.signer ?? requireSigner(acct);
        return transact(
          stateStore,
          {
            account: acct,
            signer,
            chainId: params.chainId,
            poolAddress: params.poolAddress,
            transactions: params.transactions,
          },
          { ...txOpts, ...opts },
        );
      },
      reconcile: async (relayId: string) => {
        const result = (await reconciler.reconcileRelay(
          relayId,
        )) as TransactSyncResult;
        const account = await requireActiveAccount();
        await historyService.rebuildHistory({
          chainId: result.chainId,
          mpk: formatUint256(account.masterPublicKey),
        });
        return result;
      },
    },
    transfer: {
      async plan(
        params: SendParams,
        account?: AccountView,
      ): Promise<SendPlanResult> {
        ensureChainId(params.chainId);

        // Get sender account for change outputs
        const acct = account ?? (await requireActiveAccount());

        // Get all unspent notes for the active account
        const notes = await stateStore.listNotes({
          chainId: params.chainId,
          mpk: formatUint256(acct.masterPublicKey),
          includeSpent: false,
        });

        // Plan the transfers (handles note tracking across multiple transfers)
        return planTransfers(
          notes,
          params.transfers.map((t) => {
            const parsed = parseZkAddress(t.recipient);
            return {
              token: t.token,
              amount: t.amount,
              recipientMpk: parsed.masterPublicKey,
              recipientViewingPubKey: parsed.viewingPublicKey,
            };
          }),
          acct.masterPublicKey,
          acct.viewingKeyPair.pubkey,
        );
      },
      async execute(
        plans: SendPlanResult,
        params: Pick<SendParams, "chainId" | "poolAddress">,
        overrides?: SignerOverride,
      ): Promise<SendResult> {
        const acct = overrides?.account ?? (await requireActiveAccount());
        const signer = overrides?.signer ?? requireSigner(acct);

        // Build transaction params from individual plans
        const transactions = plans.map((plan) => ({
          token: plan.token,
          inputs: plan.inputs.map((note: NoteRecord) => ({
            index: note.index,
          })),
          outputs: plan.outputNotes,
        }));

        // Execute with parallel proof generation
        const transactResult = await transact(
          stateStore,
          {
            account: acct,
            signer,
            chainId: params.chainId,
            poolAddress: params.poolAddress,
            transactions,
          },
          txOpts,
        );

        return {
          relayId: transactResult.relayId,
          plans,
          transactResult,
        };
      },
      async send(
        params: SendParams,
        overrides?: SignerOverride,
      ): Promise<SendResult> {
        const plans = await this.plan(params, overrides?.account);
        return this.execute(plans, params, overrides);
      },
    },
    withdraw: {
      async plan(
        params: WithdrawParams,
        account?: AccountView,
      ): Promise<WithdrawPlanResult> {
        ensureChainId(params.chainId);

        // Get sender account for change outputs
        const acct = account ?? (await requireActiveAccount());

        // Get all unspent notes for the active account
        const notes = await stateStore.listNotes({
          chainId: params.chainId,
          mpk: formatUint256(acct.masterPublicKey),
          includeSpent: false,
        });

        // Plan the withdrawals (handles note tracking across multiple withdrawals)
        return planWithdrawals(
          notes,
          params.withdrawals.map((w) => ({
            token: w.token,
            amount: w.amount,
            recipient: w.recipient,
          })),
          acct.masterPublicKey,
          acct.viewingKeyPair.pubkey,
        );
      },
      async execute(
        plans: WithdrawPlanResult,
        params: Pick<WithdrawParams, "chainId" | "poolAddress">,
        overrides?: SignerOverride,
      ): Promise<WithdrawResult> {
        const acct = overrides?.account ?? (await requireActiveAccount());
        const signer = overrides?.signer ?? requireSigner(acct);

        // Build transaction params from individual plans
        const transactions = plans.map((plan) => ({
          token: plan.token,
          inputs: plan.inputs.map((note: NoteRecord) => ({
            index: note.index,
          })),
          outputs: plan.outputNotes,
          withdrawal: plan.withdrawal,
        }));

        // Execute with parallel proof generation
        const transactResult = await transact(
          stateStore,
          {
            account: acct,
            signer,
            chainId: params.chainId,
            poolAddress: params.poolAddress,
            transactions,
          },
          txOpts,
        );

        return {
          relayId: transactResult.relayId,
          plans,
          transactResult,
        };
      },
      async send(
        params: WithdrawParams,
        overrides?: SignerOverride,
      ): Promise<WithdrawResult> {
        const plans = await this.plan(params, overrides?.account);
        return this.execute(plans, params, overrides);
      },
    },
    events: {
      on: (fn: (event: WalletSDKEvent) => void) => events.on(fn),
    },
    sync: {
      async syncChain(
        chainId: number,
        account: AccountView,
        opts?: { forceFullResync?: boolean },
      ) {
        await syncService.syncChain(chainId, account, opts);
        await historyService.rebuildHistory({
          chainId,
          mpk: formatUint256(account.masterPublicKey),
        });
        events.emit({ type: "notes-updated", chainId });
      },
      async syncChains(
        chainIds: number[],
        account: AccountView,
        opts?: { forceFullResync?: boolean },
      ) {
        await syncService.syncChains(chainIds, account, opts);
        await Promise.all(
          chainIds.map((chainId) =>
            historyService.rebuildHistory({
              chainId,
              mpk: formatUint256(account.masterPublicKey),
            }),
          ),
        );
        chainIds.forEach((id) =>
          events.emit({ type: "notes-updated", chainId: id }),
        );
      },
      async startAutoSync(intervalMs?: number) {
        console.log("[sdk] starting auto-sync");
        scheduler.start(intervalMs);
      },
      stopAutoSync() {
        scheduler.stop();
      },
    },
    tx: {
      async getStatus(txId: string): Promise<RelayStatusResponse> {
        // Broadcaster accepts both relay_id (ULID) and client_tx_id (UUID)
        return broadcasterClient.getRelayStatus(txId);
      },
      track(txId: string): void {
        txTracker.track(txId);
      },
      untrack(txId: string): void {
        txTracker.untrack(txId);
      },
    },
  };

  return sdk;
}

/**
 * Options for createBrowserWalletSDK.
 * Either provide a chain name to auto-resolve, or explicit gatewayUrl + poolAddress.
 */
export type BrowserWalletOptions =
  | {
      chain: SupportedChain;
      poolAddress?: string;
      prover?: ServiceOptions["prover"];
    }
  | {
      chainId?: number;
      gatewayUrl: string;
      poolAddress: string;
      prover?: ServiceOptions["prover"];
    };

/**
 * Result from createBrowserWalletSDK including SDK and resolved config.
 */
export type BrowserWalletResult = {
  sdk: WalletSDK;
  config: {
    gatewayUrl: string;
    poolAddress: string;
    artifactVersion?: string;
    artifactBaseUrl?: string;
  };
};

/**
 * @internal Use {@link Unlink.create} instead.
 */
export async function createBrowserWalletSDK(
  options: BrowserWalletOptions,
): Promise<BrowserWalletResult> {
  let chainId: number | undefined;
  let gatewayUrl: string;
  let poolAddress: string;
  let prover = options.prover;

  if ("chain" in options) {
    // Resolve from chain config
    const chainConfig = await fetchChainConfig(options.chain);
    chainId = chainConfig.chainId;
    gatewayUrl = chainConfig.gatewayUrl;
    poolAddress = options.poolAddress ?? chainConfig.poolAddress;
    prover = {
      artifactSource: {
        baseUrl:
          options.prover?.artifactSource?.baseUrl ??
          chainConfig.artifactBaseUrl,
        version:
          options.prover?.artifactSource?.version ??
          chainConfig.artifactVersion,
        preferLocalFiles: options.prover?.artifactSource?.preferLocalFiles,
      },
    };
  } else {
    // Explicit config provided
    chainId = options.chainId;
    gatewayUrl = options.gatewayUrl;
    poolAddress = options.poolAddress;

    if (
      typeof window !== "undefined" &&
      !options.prover?.artifactSource?.version
    ) {
      throw new InitializationError(
        "prover.artifactSource.version is required in browser when using explicit gatewayUrl mode. Use chain mode or provide a pinned artifact version.",
      );
    }
  }

  const storage = createIndexedDbStorage({ name: "unlink-wallet" });
  const rng = (n: number) => {
    if (!globalThis.crypto?.getRandomValues) {
      throw new Error(
        "crypto.getRandomValues unavailable; provide rng manually",
      );
    }
    return globalThis.crypto.getRandomValues(new Uint8Array(n));
  };
  const core = await initCore({ storage, rng });
  const sdk = createWalletSDK(
    {
      core,
      fetch: globalThis.fetch,
    },
    { chainId, gatewayUrl, prover },
  );
  return {
    sdk,
    config: {
      gatewayUrl,
      poolAddress,
      artifactVersion: prover?.artifactSource?.version,
      artifactBaseUrl: prover?.artifactSource?.baseUrl,
    },
  };
}
