import { Interface } from "ethers";

import { AdapterError } from "../errors.js";
import { ensureAddress } from "../utils/validators.js";
import type {
  AdapterExecutionCall,
  AdapterExecutionReshield,
} from "./transact.js";

export type {
  AdapterExecutionCall,
  AdapterExecutionReshield,
} from "./transact.js";

export const ADAPTER_EXECUTE_ABI = [
  "function execute(bytes _transactData, (address to, bytes data, uint256 value)[] _calls, (uint256 npk, uint256 random, address token, uint256 minAmount)[] _reshields, address[] _inputTokens, uint256 _nonce, uint256 _deadline)",
] as const;

const adapterInterface = new Interface(ADAPTER_EXECUTE_ABI);
const approveInterface = new Interface([
  "function approve(address spender, uint256 amount)",
]);
const HEX_DATA_REGEX = /^0x[0-9a-fA-F]*$/;

export type BuildCallParams = {
  to: string;
  abi: string;
  functionName: string;
  args: unknown[];
  value?: bigint;
};

export type EncodeAdapterExecuteParams = {
  transactCalldata: string;
  calls: AdapterExecutionCall[];
  reshields: AdapterExecutionReshield[];
  inputTokens: string[];
  nonce: bigint;
  deadline: bigint;
};

function ensureNonNegative(label: string, value: bigint): bigint {
  if (value < 0n) {
    throw new AdapterError(`${label} must be non-negative`);
  }
  return value;
}

function ensureHexData(label: string, value: string): string {
  if (
    typeof value !== "string" ||
    !HEX_DATA_REGEX.test(value) ||
    value.length % 2 !== 0
  ) {
    throw new AdapterError(`${label} must be 0x-prefixed even-length hex data`);
  }
  return value;
}

function normalizeCall(
  call: AdapterExecutionCall,
  index: number,
): AdapterExecutionCall {
  const to = ensureAddress(`calls[${index}].to`, call.to);
  const data = ensureHexData(`calls[${index}].data`, call.data);
  const value = ensureNonNegative(`calls[${index}].value`, call.value);
  return { to, data, value };
}

function normalizeReshield(
  reshield: AdapterExecutionReshield,
  index: number,
): AdapterExecutionReshield {
  const token = ensureAddress(`reshields[${index}].token`, reshield.token);
  const npk = ensureNonNegative(`reshields[${index}].npk`, reshield.npk);
  const random = ensureNonNegative(
    `reshields[${index}].random`,
    reshield.random,
  );
  const minAmount = ensureNonNegative(
    `reshields[${index}].minAmount`,
    reshield.minAmount,
  );

  return { npk, random, token, minAmount };
}

/**
 * Build a single adapter call from ABI metadata.
 */
export function buildCall(params: BuildCallParams): AdapterExecutionCall {
  const to = ensureAddress("call.to", params.to);
  if (typeof params.abi !== "string" || params.abi.trim().length === 0) {
    throw new AdapterError("call.abi must be a non-empty ABI fragment string");
  }
  if (
    typeof params.functionName !== "string" ||
    params.functionName.trim().length === 0
  ) {
    throw new AdapterError("call.functionName must be a non-empty string");
  }
  if (!Array.isArray(params.args)) {
    throw new AdapterError("call.args must be an array");
  }

  const value = ensureNonNegative("call.value", params.value ?? 0n);

  let iface: Interface;
  try {
    iface = new Interface([params.abi]);
  } catch (err) {
    throw new AdapterError(
      `invalid ABI fragment for call: ${err instanceof Error ? err.message : String(err)}`,
    );
  }

  let data: string;
  try {
    data = iface.encodeFunctionData(params.functionName, params.args);
  } catch (err) {
    throw new AdapterError(
      `failed to encode ${params.functionName}: ${err instanceof Error ? err.message : String(err)}`,
    );
  }

  return { to, data, value };
}

/**
 * Build a standard ERC-20 approve call for adapter execution.
 */
export function approve(
  token: string,
  spender: string,
  amount: bigint,
): AdapterExecutionCall {
  const normalizedToken = ensureAddress("token", token);
  const normalizedSpender = ensureAddress("spender", spender);
  const normalizedAmount = ensureNonNegative("amount", amount);

  const data = approveInterface.encodeFunctionData("approve", [
    normalizedSpender,
    normalizedAmount,
  ]);

  return {
    to: normalizedToken,
    data,
    value: 0n,
  };
}

/**
 * Loose transaction-like input accepted by {@link toCall}.
 * Structurally compatible with ethers v6 `ContractTransaction`,
 * `PreparedTransactionRequest`, and `TransactionRequest` without
 * importing ethers types.
 */
export type TransactionLike = {
  to?: string | null;
  data?: string | null;
  value?: bigint | number | string | null;
};

/**
 * Convert a transaction-like object (e.g. from ethers
 * `Contract.method.populateTransaction(...)`) into an
 * {@link AdapterExecutionCall}.
 */
export function toCall(tx: TransactionLike): AdapterExecutionCall {
  if (tx.to == null) {
    throw new AdapterError("tx.to is required");
  }
  const to = ensureAddress("tx.to", tx.to);

  if (tx.data == null) {
    throw new AdapterError("tx.data is required");
  }
  const data = ensureHexData("tx.data", tx.data);

  let value: bigint;
  if (tx.value == null) {
    value = 0n;
  } else {
    try {
      value = BigInt(tx.value);
    } catch {
      throw new AdapterError(
        `tx.value must be convertible to bigint, received: ${String(tx.value)}`,
      );
    }
  }

  return { to, data, value: ensureNonNegative("tx.value", value) };
}

/**
 * Create a contract proxy that encodes method calls into
 * {@link AdapterExecutionCall} objects. Similar to ethers `Contract`
 * but synchronous and returns calldata instead of executing.
 *
 * @example
 * ```ts
 * const router = contract(routerAddress, [
 *   "function exactInputSingle((address,address,uint24,address,uint256,uint256,uint160)) returns (uint256)",
 * ]);
 * const call = router.exactInputSingle(tokenIn, tokenOut, 3000, recipient, amountIn, minOut, 0);
 * ```
 */
export function contract(
  address: string,
  abi: ReadonlyArray<string>,
): Record<string, (...args: unknown[]) => AdapterExecutionCall> {
  const to = ensureAddress("contract.address", address);
  const iface = new Interface(abi as string[]);

  return new Proxy(
    {} as Record<string, (...args: unknown[]) => AdapterExecutionCall>,
    {
      get(_, method: string) {
        return (...args: unknown[]): AdapterExecutionCall => {
          const data = iface.encodeFunctionData(method, args);
          return { to, data, value: 0n };
        };
      },
    },
  );
}

/**
 * Encode `UnlinkAdapter.execute(...)` calldata.
 */
export function encodeAdapterExecute(
  params: EncodeAdapterExecuteParams,
): string {
  const transactCalldata = ensureHexData(
    "transactCalldata",
    params.transactCalldata,
  );
  const calls = params.calls.map((call, i) => normalizeCall(call, i));
  const reshields = params.reshields.map((reshield, i) =>
    normalizeReshield(reshield, i),
  );
  const inputTokens = params.inputTokens.map((token, i) =>
    ensureAddress(`inputTokens[${i}]`, token),
  );
  const nonce = ensureNonNegative("nonce", params.nonce);
  const deadline = ensureNonNegative("deadline", params.deadline);

  return adapterInterface.encodeFunctionData("execute", [
    transactCalldata,
    calls,
    reshields,
    inputTokens,
    nonce,
    deadline,
  ]);
}

/** @deprecated Use {@link approve} instead. */
export const buildApproveCall = approve;
